const EXAMS = [{"id": 1, "title": "Đề 1", "count": 10, "duration_minutes": 15, "questions": [{"id": 85, "q": "Phân loại theo lĩnh vực Hành chính nhà nước thì TTHC” Đăng ký xe từ điểm đăng ký xe khác chuyển đến” thuộc loại nào?", "options": {"A": "TTHC cấp xã thực hiện", "B": "Đăng ký, quản lý phương tiện giao thông mô tô và xe gắn máy", "C": "Đăng ký, quản lý phương tiện giao thông cơ giới, xe máy chuyên dùng", "D": "TTHC cấp tỉnh thực hiện"}, "correct": "C"}, {"id": 97, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây là quy định hành vi bị nghiêm cấm của cán bộ,công chức được phân công thực hiện TTHC", "options": {"A": "Tất cả các phương án trên", "B": "Tù chối thực hiện, kéo dài thời gian thực hiện hoặc tự ý yêu cầu bổ sung thêm hồ sơ, giấy tờ ngoài quy định mà không nêu rõ lý lo bằng văn bản", "C": "Hách dịch, cửa quyền,sách nhiễu, gây phiền hà, gây khó khăn cho đối tượng thực hiện TTHC", "D": "đùn đẩy trách nhiệm, thiếu hợp tác, chậm trễ, gây cản trở trong thực hiện nhiệm vụ được giao"}, "correct": "A"}, {"id": 66, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "B": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân.", "C": "Kiểm soát TTHC có hiệu quả là hoạt động mang lại lợi ích trực  tiếp cho các cá nhân, tổ chức nhưng đồng thời không để sơ hở  trong công tác quản lý nhà nước. Thực tế đã chỉ ra rằng, nếu không làm tốt công tác giám sát, kiểm  soát TTHC thì các hoạt động nhằm cải cách thủ tục hành chính đôi  khi chỉ mang tính hình thức", "D": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật"}, "correct": "C"}, {"id": 41, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "B": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "C": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "D": "Hỗ trợ người có công, người cao tuổi, người tàn tật, người nghèo, phụ nữ mang thai, trẻ mồ côi và người thuộc diện bảo trợ xã hội khác trong thực hiện thủ tục hành chính."}, "correct": "D"}, {"id": 109, "q": "bản chính giấy tờ, văn bản trong phương án nào dưới đây được dùng làm cơ sở để chứng thực phản sao trong thủ tục” Chứng thực bản sao từ bản chính giấy tờ, văn bản do cơ quan tổ chức có thẩm quyền của VN cấp hoặc chứng nhận”?", "options": {"A": "bản chính giấy tờ, văn bản đóng dấu mật của cơ quan, tổ chức có thẩm quyền", "B": "Bản sao công chứng giấy chứng nhận quyền sử dụng đất", "C": "giấy khai sinh bản sao", "D": "Giấy khai sinh bản chính do cơ quan có thẩm quyền cấp"}, "correct": "A"}, {"id": 13, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Đơn giản, dễ hiểu và dễ thực hiện", "B": "Quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế", "C": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính", "D": "Linh hoạt theo yêu cầu triển khai pháp luật vào đời sống"}, "correct": "A"}, {"id": 73, "q": "Phân loại theo lĩnh vực  quản lý hành chính nhà nước thì thủ tục hành chính “ Đăng ký khai tử” thuộc lĩnh vực nào sau đây", "options": {"A": "Lĩnh vực quốc tịch", "B": "Lĩnh vực hội tịch", "C": "Lĩnh vực tư pháp", "D": "Lĩnh vực cư trú"}, "correct": "B"}, {"id": 54, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Hướng dẫn, giải thích, cung cấp thông tin chính xác, đầy đủ, kịp thời về thủ tục hành chính cho cá nhân, tổ chức có liên quan.", "B": "Từ chối thực hiện những yêu cầu không được quy định trong thủ tục hành chính hoặc chưa được công khai theo quy định", "C": "Thực hiện cơ chế một cửa, một cửa liên thông trong thực hiện thủ tục hành chính", "D": "Thực hiện nghiêm túc, đầy đủ nhiệm vụ được giao trong quá trình thực hiện thủ tục hành chính"}, "correct": "B"}, {"id": 49, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Hướng dẫn, giải thích, cung cấp thông tin chính xác, đầy đủ, kịp thời về thủ tục hành chính cho cá nhân, tổ chức có liên quan", "B": "Không tự đặt ra thủ tục hành chính, hồ sơ, giấy tờ ngoài quy định của pháp luật", "C": "Phối hợp và chia sẻ thông tin trong quá trình giải quyết công việc của cá nhân, tổ chức", "D": "Hướng dẫn tổ chức, cá nhân thực hiện trình tự, hồ sơ hành chính đầy đủ, rõ ràng, chính xác không để tổ chức, cá nhân phải đi lại bổ sung hồ sơ quá hai lần cho một vụ việc, trừ trường hợp tổ chức, cá nhân thực hiện không đúng theo hướng dẫn của cán bộ, công chức được phân công thực hiện thủ tục hành chính"}, "correct": "D"}, {"id": 11, "q": "Đâu là ý nghĩa của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính có sự linh hoạt theo yêu cầu triển khai pháp luật vào đời sống", "B": "Thủ tục hành chính có tính đa dạng, phức tạp", "C": "Thủ tục hành chính là quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế", "D": "Thủ tục hành chính biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính"}, "correct": "D"}]}, {"id": 2, "title": "Đề 2", "count": 10, "duration_minutes": 15, "questions": [{"id": 47, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Cấp giấy biên nhận hồ sơ, tài liệu theo quy định.", "B": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính", "C": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định", "D": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính"}, "correct": "B"}, {"id": 14, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Bảo đảm tính liên thông, kịp thời, chính xác, không gây phiền hà trong thực hiện thủ tục hành chính", "B": "Phù hợp với mục tiêu quản lý hành chính nhà nước", "C": "Được thực hiện một cách thống nhất", "D": "Linh hoạt theo yêu cầu triển khai pháp luật vào đời sống"}, "correct": "B"}, {"id": 74, "q": "Phương án nào dưới đây là đặc điểm của TTHC", "options": {"A": "TTHC có sự linh hoạt theo yêu cầu triển khai PL vào Đs", "B": "TTHC thể hiện mức độ văn minh của nền hành chính", "C": "TTHC được  thực hiện giải quyết công việc cho người dân", "D": "TTHC là quy phạm pháp luật đơn giản dễ hiểu, phù hợp với mục tiêu Qli"}, "correct": "A"}, {"id": 45, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước", "options": {"A": "Hướng dẫn tổ chức, cá nhân thực hiện trình tự, hồ sơ hành chính đầy đủ, rõ ràng, chính xác không để tổ chức, cá nhân phải đi lại bổ sung hồ sơ quá hai lần cho một vụ việc, trừ trường hợp tổ chức, cá nhân thực hiện không đúng theo hướng dẫn của cán bộ, công chức được phân công thực hiện thủ tục hành chính", "B": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "C": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "D": "Thực hiện quy định khác của pháp luật"}, "correct": "D"}, {"id": 65, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "B": "Việc kiểm soát TTHC để nâng cao chất lượng hệ thống các quy định hành chính.", "C": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân.", "D": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính"}, "correct": "B"}, {"id": 53, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Thực hiện đầy đủ các quy định về thủ tục hành chính.", "B": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính", "C": "Không tự đặt ra thủ tục hành chính, hồ sơ, giấy tờ ngoài quy định của pháp luật", "D": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính"}, "correct": "A"}, {"id": 110, "q": "Phương án nào sau đây không phải nội dung đăng ký hộ tịch", "options": {"A": "XN vào sổ hộ tịch sự kiệp cấp căn cước công dân", "B": "XN vào sổ hộ tịch sự kiện giám hộ", "C": "---------------------------------------- sự kiện xác định lại dân tộc", "D": "Nhận cha mẹ con"}, "correct": "A"}, {"id": 9, "q": "Đâu là ý nghĩa của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính được thực hiện một cách thống nhất", "B": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "C": "Thủ tục hành chính có tính đa dạng, phức tạp", "D": "Thủ tục hành chính do cơ quan nhà nước, người có thẩm quyền quy định"}, "correct": "B"}, {"id": 86, "q": "Theo quy định của pháp luật hiện hành, Bộ phận một cửa cấp xã do cơ quan hay cá nhân quyết định thành lập", "options": {"A": "Chủ tịch ubnd cấp tỉnh", "B": "Chủ tịch ubnd xã", "C": "UBND cấp tỉnh", "D": "UBND cấp xã"}, "correct": "D"}, {"id": 98, "q": "23. Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung, phương án nào dưới đây là nguyên tắc tiếp nhận, xử lý phản ánh kiến nghị của cá nhân tổ chức về quy định hành chính", "options": {"A": "Hợp tình, hợp lý", "B": "Nhanh chóng, khách quan", "C": "công khai minh bạc", "D": "Công bằng, ngắn gọn"}, "correct": "B"}]}, {"id": 3, "title": "Đề 3", "count": 10, "duration_minutes": 15, "questions": [{"id": 99, "q": "23. Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung” tiếp nhận và giải quyết hồ sơ cá nhân, tổ chức theo quy định” là trách nhiệm của cơ quan hay cá nhân nào dưới đây", "options": {"A": "Cơ quan thực hiện TTHC", "B": "Cán bộ, công chức quy định TTHC", "C": "Cán bộ, cc được phân công thực hiện TTHC", "D": "Chủ tịch Ubnd cấp xã"}, "correct": "C"}, {"id": 16, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính", "B": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "C": "Bảo đảm quyền bình đẳng của các đối tượng thực hiện thủ tục hành chính", "D": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được"}, "correct": "C"}, {"id": 87, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi, bổ sung phương án nào dưới đây là nguyên tắc thực hiện TTHC?", "options": {"A": "Đảm bảo tính hợp hiến, hợp pháp, của các quy định về TTHC", "B": "Bảo đảm tính liên thông, kịp thời, không gây phiền hà trong thực hiện TTHC", "C": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước", "D": "Đơn giản, dễ hiểu và thực hiện"}, "correct": "B"}, {"id": 51, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính", "B": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "C": "Thực hiện cơ chế một cửa, một cửa liên thông trong thực hiện thủ tục hành chính", "D": "Bảo quản và giữ bí mật về hồ sơ tài liệu và các thông tin liên quan đến bí mật cá nhân trong quá trình giải quyết theo quy định của pháp luật, trừ trường hợp phải thu thập, công bố thông tin, tư liệu theo quyết định của cơ quan, tổ chức nhà nước có thẩm quyền"}, "correct": "B"}, {"id": 37, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "B": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "C": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính.", "D": "Bảo quản và giữ bí mật về hồ sơ tài liệu và các thông tin liên quan đến bí mật cá nhân trong quá trình giải quyết theo quy định của pháp luật, trừ trường hợp phải thu thập, công bố thông tin, tư liệu theo quyết định của cơ quan, tổ chức nhà nước có thẩm quyền"}, "correct": "D"}, {"id": 75, "q": "TTHC nào dưới đây được phân loại theo ngành lĩnh vực quản lý hành chính nhà nước", "options": {"A": "TTHC địa phương", "B": "TTHC trung ương", "C": "TTHC về cư trú", "D": "TTHC liên hệ"}, "correct": "B"}, {"id": 59, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "B": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính", "C": "Khiếu nại, tố cáo, khởi kiện các quyết định hành chính và hành vi hành chính theo quy định của pháp luật", "D": "Bảo quản và giữ bí mật về hồ sơ tài liệu và các thông tin liên quan đến bí mật cá nhân trong quá trình giải quyết theo quy định của pháp luật, trừ trường hợp phải thu thập, công bố thông tin, tư liệu theo quyết định của cơ quan, tổ chức nhà nước có thẩm quyền"}, "correct": "C"}, {"id": 111, "q": "Phương án nào dưới đây là trường hợp không được miễn lệ phí khi thực hiện thủ tục” đăng ký khai sinh”( cho công dân VN cư trú ở trong nước)", "options": {"A": "thuộc hộ nghèo", "B": "Gia đình có công với cách mạng", "C": "không đúng hạn", "D": "Đúng hạn"}, "correct": "C"}, {"id": 2, "q": "Đâu là đặc điểm của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "B": "Thủ tục hành chính là quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế", "C": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "D": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện"}, "correct": "B"}, {"id": 71, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "B": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "C": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "D": "Bổ sung thủ tục hành chính cần thiết, đáp ứng nhu cầu thực tế;"}, "correct": "D"}]}, {"id": 4, "title": "Đề 4", "count": 10, "duration_minutes": 15, "questions": [{"id": 100, "q": "Theo quy định của Pháp luật hiện hành, căn cứ số lượng TTHC thuộc thẩm quyền giải quyết, tần suất tiếp nhận hồ sơ và tình hình bố trí trụ sở Bộ phận tiếp nhận và trả kết quả tại bộ, cơ quan ngang bộ do cơ quan hay cá nhân nào quyết định thành lập", "options": {"A": "bộ, cơ quan ngang bộ", "B": "Thủ tướng chính phủ", "C": "Chính phủ", "D": "Bộ trưởng, Thủ trưởng cơ quan ngang bộ"}, "correct": "D"}, {"id": 68, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "Kiểm soát thủ tục hành chính đáp ứng yêu cầu công khai, minh bạch trong quá trình tổ chức thực hiện thủ tục hành chính.", "B": "bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "C": "bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "D": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân."}, "correct": "A"}, {"id": 18, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "B": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính", "C": "Bảo đảm tính liên thông, kịp thời, chính xác, không gây phiền hà trong thực hiện thủ tục hành chính", "D": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước"}, "correct": "D"}, {"id": 76, "q": "PL theo quan hệ công tác thì TTHC “ Cấp lại giấy phép lao động nước ngoài làm việc tại Việt nam” thuộc loại nào dưới đây", "options": {"A": "TTHC nội bộ", "B": "TTHC Cấp tỉnh thực hiện", "C": "TTHC cấp xã thực hiện", "D": "TTHC liên hệ"}, "correct": "D"}, {"id": 44, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước", "options": {"A": "Hướng dẫn tổ chức, cá nhân thực hiện trình tự, hồ sơ hành chính đầy đủ, rõ ràng, chính xác không để tổ chức, cá nhân phải đi lại bổ sung hồ sơ quá hai lần cho một vụ việc, trừ trường hợp tổ chức, cá nhân thực hiện không đúng theo hướng dẫn của cán bộ, công chức được phân công thực hiện thủ tục hành chính", "B": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "C": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính", "D": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố"}, "correct": "C"}, {"id": 28, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Đối tượng giải quyết", "B": "Chủ thể thực hiện", "C": "Cơ quan giải quyết thủ tục hành chính", "D": "Nơi nhận"}, "correct": "C"}, {"id": 50, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "B": "Bảo quản và giữ bí mật về hồ sơ tài liệu và các thông tin liên quan đến bí mật cá nhân trong quá trình giải quyết theo quy định của pháp luật, trừ trường hợp phải thu thập, công bố thông tin, tư liệu theo quyết định của cơ quan, tổ chức nhà nước có thẩm quyền", "C": "Không tự đặt ra thủ tục hành chính, hồ sơ, giấy tờ ngoài quy định của pháp luật", "D": "Hướng dẫn, giải thích, cung cấp thông tin chính xác, đầy đủ, kịp thời về thủ tục hành chính cho cá nhân, tổ chức có liên quan"}, "correct": "A"}, {"id": 88, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây là nguyên tắc thực hiện TTHC?", "options": {"A": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "B": "Tiết kiệm thời gian  và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước", "C": "phù hợp với mục tiêu ql", "D": "Đảm bảo tính đồng bộ, hiệu quả của các quy định về TTHC"}, "correct": "A"}, {"id": 112, "q": "Phương án nào dưới đây là 1 trong các giấy tờ cần nộp để thực hiện thủ tục “ chứng thực bản sao từ bản chính giấy tờ, văn bản do cơ quan tổ chức có thẩm quyền của VN cấp hoặc chứng nhận”", "options": {"A": "căn cước công dân đã được cơ quan có thẩm quyền chứng thực", "B": "Bản chính giấy tờ, văn bản do cơ quan tổ chức có thẩm quyền của Vn cấp hoặc chứng nhận", "C": "Giấy tờ chứng minh nơi cư trú để xác định cơ quan có thẩm quyền thực hiện", "D": "Văn bản đồng ý cho thực hiện chứng thực của người có thẩm quyền."}, "correct": "B"}, {"id": 5, "q": "Đâu là đặc điểm của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "B": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "C": "Thủ tục hành chính biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "D": "Thủ tục hành chính có tính đa dạng, phức tạp"}, "correct": "D"}]}, {"id": 5, "title": "Đề 5", "count": 9, "duration_minutes": 15, "questions": [{"id": 89, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung cá nhân hay cơ quan nào dưới đây không có thẩm quyền công bố TTHC", "options": {"A": "UBND cấp xã", "B": "Chủ tịch UBND tỉnh, thành phố trực thuộc trung ương", "C": "Bộ trưởng, Thủ trưởng cơ quan ngang bộ", "D": "Người đứng đầu cơ quan, đơn vị được cơ quan nhà nước cấp trên giao nhiệm vụ hoặc ủy quyền ban hành văn bản hướng dẫn thực hiện thủ tục giải quyết công việc cho cá nhân, tổ chứ"}, "correct": "A"}, {"id": 46, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Thực hiện nghiêm túc, đầy đủ nhiệm vụ được giao trong quá trình thực hiện thủ tục hành chính", "B": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định", "C": "Cấp giấy biên nhận hồ sơ, tài liệu theo quy định.", "D": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính"}, "correct": "A"}, {"id": 101, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây không phải là nội dung rà soát, đánh giá TTHC", "options": {"A": "Các nguyên tắc quy định  TTHC theo quy định pháp luật", "B": "Các nguyên tắc thực hiện TTHC theo quy định Pl", "C": "Sự đầy đủ số lượng văn bản TTHC", "D": "Tính hợp pháp của TTHC, quy định có liên quan đến TTHC"}, "correct": "C"}, {"id": 27, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Nội dung thủ tục", "B": "Đối tượng thực hiện thủ tục hành chính", "C": "Cơ quan thực hiện thủ tục", "D": "Chủ thể thực hiện thủ tục"}, "correct": "B"}, {"id": 63, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "Kiểm soát thủ tục hành chính góp phần xây dựng nền hành chính chuyên nghiệp, hiệu quả và hiện đại.", "B": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân.", "C": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "D": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính"}, "correct": "A"}, {"id": 77, "q": "PL dựa trên quan hệ công tác của cơ quan hành chính nhà nước thì TTHC” Cấp phiếu lý lịch tư pháp cho công dân VN, người nước ngoài đang cư trú tại Việt Nam” thuộc loại TTHC nào trong các Phương án", "options": {"A": "TTHC công an xã", "B": "TTHC của Sở Tư Pháp", "C": "TTHC nội bộ", "D": "TTHC liên hệ"}, "correct": "B"}, {"id": 3, "q": "Đặc điểm nào sau đây là đặc điểm của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "B": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "C": "Thủ tục hành chính do cơ quan nhà nước, người có thẩm quyền quy định", "D": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện"}, "correct": "C"}, {"id": 42, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Thực hiện cơ chế một cửa, một cửa liên thông trong thực hiện thủ tục hành chính", "B": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "C": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "D": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định."}, "correct": "A"}, {"id": 17, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Bảo đảm quyền được phản ánh, kiến nghị của các cá nhân, tổ chức đối với các thủ tục hành chính", "B": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "C": "Bảo đảm quyền bình đẳng của các đối tượng thực hiện thủ tục hành chính", "D": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được"}, "correct": "C"}]}, {"id": 6, "title": "Đề 6", "count": 9, "duration_minutes": 15, "questions": [{"id": 102, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây là trách nhiệm của cán bộ, công chức được phân công thực hiện TTHC", "options": {"A": "Hỗ trợ người có công, người cao tuổi, người tàn tật,người nghèo, yêu phụ nữ mang thai, trẻ mồ côi, và người thuộc diện bảo trợ xã hội khác trong thực hiện TTHC", "B": "Chịu trách nhiệm công bố, tổ chức nhập dữ liệu về TTHC đã công bố trên cơ sở dữ liệu quốc gia về TTHC theo quy định", "C": "Chịu trách nhiệm về tính hợp pháp, chính xác của các giấy tờ có trong hồ sơ và cung cấp đầy đủ thông tin có liên quan.", "D": "Chấp hành nhiêm túc các quy định của cấp có thẩm quyền về TTHC đã được người đứng đầu Bộ ,cơ quan ngang bộ, UBND tỉnh, thành phố trực thuộc Trung ương công bố"}, "correct": "D"}, {"id": 78, "q": "PL theo lĩnh vực quản lý hành chính nhà nước TTHC” thông báo lưu trú” thuộc lĩnh vực", "options": {"A": "Lĩnh vực lưu trú", "B": "Lĩnh vực đăng kí, quản lý lưu trú", "C": "Lĩnh vực lý lịch tư pháp", "D": "Lĩnh vực hộ tịch"}, "correct": "A"}, {"id": 30, "q": "Nguyên tắc nào sau đây là nguyên tắc thực hiện thủ tục hành chính?", "options": {"A": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước", "B": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính", "C": "Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "D": "Phù hợp với mục tiêu quản lý hành chính nhà nước"}, "correct": "B"}, {"id": 90, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây không thuộc nội dung rà soát, đánh giá thủ tục hành chính?", "options": {"A": "Tính hợp pháp của TTHC", "B": "Sự ngắn gọn của TTHC", "C": "Chí phí tuân thủ của TTHC", "D": "Sự cần thiết của TTHC"}, "correct": "B"}, {"id": 21, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính", "B": "Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "C": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "D": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được"}, "correct": "B"}, {"id": 70, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "B": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "C": "Kịp thời phát hiện để loại bỏ hoặc chỉnh sửa thủ tục hành chính không phù hợp, phức tạp, phiền hà;", "D": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính"}, "correct": "C"}, {"id": 25, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Chủ thể giải quyết hồ sơ", "B": "Đối tượng giải quyết hồ sơ", "C": "Nơi nhận", "D": "Thành phần, số lượng hồ sơ"}, "correct": "D"}, {"id": 38, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định", "B": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "C": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định.", "D": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi"}, "correct": "A"}, {"id": 4, "q": "Đặc điểm nào sau đây là đặc điểm của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính được thực hiện một cách thống nhất", "B": "Thủ tục hành chính biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "C": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "D": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất"}, "correct": "A"}]}, {"id": 7, "title": "Đề 7", "count": 9, "duration_minutes": 15, "questions": [{"id": 43, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Hướng dẫn tổ chức, cá nhân thực hiện trình tự, hồ sơ hành chính đầy đủ, rõ ràng, chính xác không để tổ chức, cá nhân phải đi lại bổ sung hồ sơ quá hai lần cho một vụ việc, trừ trường hợp tổ chức, cá nhân thực hiện không đúng theo hướng dẫn của cán bộ, công chức được phân công thực hiện thủ tục hành chính", "B": "Tiếp nhận, xử lý các phản ánh, kiến nghị của cá nhân, tổ chức trong thực hiện thủ tục hành chính", "C": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "D": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi"}, "correct": "B"}, {"id": 72, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "Bảo đảm quy định thủ tục hành chính đơn giản, dễ hiểu, dễ thực hiện, tiết kiệm thời gian, chi phí, công sức của đối tượng và cơ quan thực hiện thủ tục hành chính.", "B": "biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "C": "là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "D": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện"}, "correct": "A"}, {"id": 91, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung “ Thực hiện nghiêm túc, đầy đủ nhiệm vụ được giao trong quá trình thực hiện TTHC” là trách nhiệm của cơ quan hay cá nhân?", "options": {"A": "Chủ tịch ubnd các cấp", "B": "Cơ quan thực hiện TTHC", "C": "cán bộ, công chức quy định TTHC", "D": "Cán bộ,cc được phân công thực hiện TTH"}, "correct": "D"}, {"id": 103, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây không phải là bộ phận tạo thành cơ bản của 1 TTHC", "options": {"A": "Đối tượng thực hiện TTHC", "B": "Lĩnh vực TTHC", "C": "Thành phần, số lượng hồ sơ", "D": "Cơ quan giải quyết TTHC"}, "correct": "B"}, {"id": 79, "q": "PL theo lĩnh vực quản lý hành chính nhà nước thì TTHC “ Cấp giấy chứng nhận đăng ký tàu cá” thuộc lv", "options": {"A": "Lĩnh vực thủy sản", "B": "Lĩnh vực dk Doanh nghiệp", "C": "Lĩnh vực doanh nghiệp", "D": "Lĩnh vực ql tàu cá"}, "correct": "A"}, {"id": 61, "q": "Đâu là khái niệm kiểm soát thủ tục hành chính?", "options": {"A": "Kiểm soát thủ tục hành chính được hiểu là việc xem xét, đánh giá, theo dõi nhằm bảo đảm tính khả thi của quy định về thủ tục hành chính, đáp ứng yêu cầu công khai, minh bạch trong quá trình tổ chức thực hiện thủ tục hành chính.", "B": "Kiểm soát thủ tục hành chính được hiểu là Giám sát việc thực hiện thủ tục hành chính; phản ánh, kiến nghị với cơ quan nhà nước, người có thẩm quyền về những bất hợp lý của thủ tục hành chính và các hành vi vi phạm của cán bộ, công chức trong thực hiện thủ tục hành chính", "C": "Kiểm soát thủ tục hành chính được hiểu là Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "D": "Kiểm soát thủ tục hành chính được hiểu là các quy phạm thủ tục của nhà nước về cách thức tiến hành các hoạt động quản lý hành chính nên chúng tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợ ích chính đáng của các tổ chức và cá nhân"}, "correct": "A"}, {"id": 19, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "B": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được", "C": "Bảo đảm quyền được phản ánh, kiến nghị của các cá nhân, tổ chức đối với các thủ tục hành chính", "D": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước"}, "correct": "D"}, {"id": 32, "q": "Nguyên tắc nào sau đây là nguyên tắc thực hiện thủ tục hành chính?", "options": {"A": "Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "B": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước", "C": "Phù hợp với mục tiêu quản lý hành chính nhà nước", "D": "Bảo đảm quyền được phản ánh, kiến nghị của các cá nhân, tổ chức đối với các thủ tục hành chính"}, "correct": "D"}, {"id": 24, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Thành phần thực hiện", "B": "Cách thức giải quyết thủ tục hành chính", "C": "Cách thức thực hiện", "D": "Chủ thể thực hiện thủ tục"}, "correct": "C"}]}, {"id": 8, "title": "Đề 8", "count": 9, "duration_minutes": 15, "questions": [{"id": 62, "q": "Đâu là khái niệm kiểm soát thủ tục hành chính?", "options": {"A": "Kiểm soát thủ tục hành chính được hiểu là việc xem xét, đánh giá, theo dõi nhằm bảo đảm tính khả thi của quy định về thủ tục hành chính", "B": "Kiểm soát thủ tục hành chính được hiểu là đáp ứng yêu cầu công khai, minh bạch", "C": "Kiểm soát thủ tục hành chính được hiểu là trong quá trình tổ chức thực hiện thủ tục hành chính.", "D": "tất cả a,b,c"}, "correct": "D"}, {"id": 104, "q": "Trường hợp nào dưới đây không được miễn lệ phí khi thực hiện thủ tục” đăng kí khai tử” cho công dân Việt nam", "options": {"A": "TH dki khai tử không đúng hạn", "B": "Th người khuyết tất", "C": "TH người thuộc hộ nghèo", "D": "TH người thuộc gd có công cm"}, "correct": "A"}, {"id": 35, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi", "B": "Hướng dẫn, giải thích, cung cấp thông tin chính xác, đầy đủ, kịp thời về thủ tục hành chính cho cá nhân, tổ chức có liên quan.", "C": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định.", "D": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính."}, "correct": "B"}, {"id": 92, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây không là nội dung rà soát, đánh giá thủ tục hành chính", "options": {"A": "Sự cần thiết của TTHC", "B": "Sự ngắn gọn của TTHC", "C": "Tính hợp lý của TTHC", "D": "Tính hợp pháp của TTHC"}, "correct": "B"}, {"id": 31, "q": "Nguyên tắc nào sau đây là nguyên tắc thực hiện thủ tục hành chính?", "options": {"A": ". Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "B": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước", "C": "Bảo đảm tính liên thông, kịp thời, chính xác, không gây phiền hà trong thực hiện thủ tục hành chính", "D": "Phù hợp với mục tiêu quản lý hành chính nhà nước"}, "correct": "C"}, {"id": 80, "q": "Phương án nào dưới đây không phải là tiêu chí phân loại TTHC", "options": {"A": "Dựa trên quan hệ công tác của cơ quan hành chính nhà nước", "B": "Theo lĩnh vực quản lý hành chính nhà nước", "C": "Theo chủ thể quy định TTHC", "D": "Theo phân cấp ql hành chính nhà nước"}, "correct": "C"}, {"id": 22, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Tên thủ tục hành chính", "B": "Nơi nhận", "C": "Thủ trưởng cơ quan, đơn vị", "D": "Chủ thể thực hiện thủ tục hành chính"}, "correct": "A"}, {"id": 57, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Không hối lộ hoặc dùng các thủ đoạn khác để lừa dối cơ quan nhà nước, người có thẩm quyền trong thực hiện thủ tục hành chính", "B": "Hướng dẫn, giải thích, cung cấp thông tin chính xác, đầy đủ, kịp thời về thủ tục hành chính cho cá nhân, tổ chức có liên quan.", "C": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính", "D": "Hướng dẫn tổ chức, cá nhân thực hiện trình tự, hồ sơ hành chính đầy đủ, rõ ràng, chính xác không để tổ chức, cá nhân phải đi lại bổ sung hồ sơ quá hai lần cho một vụ việc, trừ trường hợp tổ chức, cá nhân thực hiện không đúng theo hướng dẫn của cán bộ, công chức được phân công thực hiện thủ tục hành chính"}, "correct": "A"}, {"id": 12, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Đơn giản, dễ hiểu và dễ thực hiện", "B": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được", "C": "Do cơ quan nhà nước, người có thẩm quyền quy định", "D": "Linh hoạt theo yêu cầu triển khai pháp luật vào đời sống"}, "correct": "A"}]}, {"id": 9, "title": "Đề 9", "count": 9, "duration_minutes": 15, "questions": [{"id": 15, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Bảo đảm tính liên thông, kịp thời, chính xác, không gây phiền hà trong thực hiện thủ tục hành chính", "B": "Phù hợp với mục tiêu quản lý hành chính nhà nước", "C": "Bảo đảm quyền được phản ánh, kiến nghị của các cá nhân, tổ chức đối với các thủ tục hành chính", "D": "Được thực hiện một cách thống nhất"}, "correct": "B"}, {"id": 93, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây là nguyên tắc kiểm soát TTHC", "options": {"A": "Kiểm soát TTHC công bằng, khách quan", "B": "Kiểm soát TTHC phải đảm bảo dúng đối tượng", "C": "Kiểm soát TTHC phải đảm bảo công khai, minh bạch", "D": "Kiểm soát TTHC phải đảm bảo thực hiện có hiệu quả mục tiêu CCHC, bảo đảm điều phối, huy động sự tham gia tích cực, rộng rãi của tất cả các cơ quan tổ chức, cá nhân vào quá trình kiểm soát TTHC"}, "correct": "D"}, {"id": 34, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính", "B": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính", "C": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định.", "D": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính"}, "correct": "A"}, {"id": 81, "q": "PL theo lĩnh vực quản lý hành chính nhà nước thì TTHC “ Cấp phiếu lý lịch tư pháp cho công dân VN, người nước ngoài đang cư trú tại VN”", "options": {"A": "Lĩnh vực hộ tịch", "B": "Lĩnh vực lý lịch tư pháp", "C": "Lĩnh vực Quốc tịch", "D": "Lĩnh vực dk, quản lý cư trú"}, "correct": "B"}, {"id": 55, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính", "B": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính", "C": "Chịu trách nhiệm về tính hợp pháp, chính xác của các giấy tờ có trong hồ sơ và cung cấp đầy đủ thông tin có liên quan", "D": "Cấp giấy biên nhận hồ sơ, tài liệu theo quy định."}, "correct": "C"}, {"id": 26, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Thời hạn giải quyết", "B": "Trình tự giải quyết hồ sơ", "C": "Chủ thể giải quyết thủ tục", "D": "Nơi nhận"}, "correct": "A"}, {"id": 1, "q": "Khái niệm thủ tục hành chính theo nghị định 63 là ?", "options": {"A": "Thủ tục hành chính là trình tự, cách thức thực hiện, hồ sơ, yêu cầu, điều kiện do cơ quan nhà nước, người có thẩm quyền quy định để giải quyết một công việc cụ thể liên quan đến cá nhân, tổ chức.", "B": "Thủ tục hành chính là “trình tự, cách thức giải quyết công việc của cơ quan hành chính nhà nước có thẩm quyền trong mối quan hệ nội bộ hành chính và mối quan hệ giữa cơ quan hành chính nhà nước với tổ chức công dân”.", "C": "Thủ tục hành chính là một loại quy phạm pháp luật quy định, trình tự, cách thức giải quyết công việc của các cơ quan nhà nước có thẩm quyền trong mối quan hệ nội bộ hành chính và mối quan hệ giữa các cơ quan nhà nước với các tổ chức và cá nhân công dân.", "D": "TTHC là trình tự, cách thức giải quyết công việc của các cơ quan nhà nước có thẩm quyền trong mối quan hệ giữa các cơ quan nhà nước với các tổ chức và cá nhân công dân mà cả trong mối quan hệ nội bộ hành chính phát sinh trong hoạt động quản lý hành chính nhà nước."}, "correct": "A"}, {"id": 29, "q": "Nguyên tắc nào sau đây là nguyên tắc thực hiện thủ tục hành chính?", "options": {"A": "Bảo đảm công khai, minh bạch các thủ tục hành chính đang được", "B": "Bảo đảm quyền bình đẳng của các đối tượng thực hiện thủ tục hành chính", "C": "Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "D": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước"}, "correct": "A"}, {"id": 105, "q": "Phương án nào dưới đây là kết quả thực hiện thủ tục “ Thi tuyển công chức”", "options": {"A": "tb kết quả thi tuyển công chức", "B": "Giấy chứng nhận trình độ chuyên môn công chức", "C": "quyết định phê duyệt kết quả", "D": "Quyết định tuyển dụng công chức"}, "correct": "D"}]}, {"id": 10, "title": "Đề 10", "count": 9, "duration_minutes": 15, "questions": [{"id": 94, "q": "cơ quan hay cá nhân nào dưới đây có thẩm quyền quy định TTHC", "options": {"A": "Chính phủ", "B": "Chủ tịch UBND cấp tỉnh", "C": "Chủ tịch ubnd cấp xã", "D": "Bộ và cơ quan ngang bộ"}, "correct": "D"}, {"id": 23, "q": "Đâu là bộ phận của một thủ tục hành chính?", "options": {"A": "Chủ thể thực hiện thủ tục hành chính", "B": "Trình tự thực hiện", "C": "Quy trình thực hiện", "D": "Nơi nhận"}, "correct": "B"}, {"id": 33, "q": "Nguyên tắc nào sau đây là nguyên tắc thực hiện thủ tục hành chính?", "options": {"A": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "B": "Phù hợp với mục tiêu quản lý hành chính nhà nước", "C": "Đơn giản, dễ hiểu và dễ thực hiện", "D": "Tiết kiệm thời gian và chi phí của cá nhân, tổ chức và cơ quan hành chính nhà nước"}, "correct": "A"}, {"id": 40, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "B": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "C": "Phối hợp và chia sẻ thông tin trong quá trình giải quyết công việc của cá nhân, tổ chức", "D": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính."}, "correct": "C"}, {"id": 6, "q": "Theo nghị định 63 đâu là đặc điểm của thủ tục hành chính ?", "options": {"A": "Thủ tục hành chính bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "B": "Thủ tục hành chính có sự linh hoạt theo yêu cầu triển khai pháp luật vào đời sống", "C": "Thủ tục hành chính biểu hiện trình độ văn hóa, văn hóa giao tiếp, văn hóa điều hành, mức độ văn minh của nền hành chính", "D": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện"}, "correct": "B"}, {"id": 82, "q": "Phương án nào dưới đây là tiêu chí phân loại TTHC", "options": {"A": "Dựa trên quan hệ công tác của cơ quan hành chính nhà nước", "B": "Theo sự xắp xếp của nhà nước", "C": "Theo chủ thể quy định TTHC", "D": "Theo đề nghị, yêu cầu của người dân"}, "correct": "A"}, {"id": 106, "q": "Phương án nào dưới đây không thuộc điều kiện thực hiện “ tt dk kết hôn”", "options": {"A": "nam nữ khác dân tộc kết hôn", "B": "Do nam và nữ tự nguyện", "C": "nam đủ 20 t, nữ 18t", "D": "Các bên không bị mất năng lực hành vi nhân sự"}, "correct": "A"}, {"id": 56, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định", "B": "Tiếp nhận, xử lý các phản ánh, kiến nghị của cá nhân, tổ chức trong thực hiện thủ tục hành chính", "C": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định.", "D": "Không được cản trở hoạt động thực hiện thủ tục hành chính của cơ quan nhà nước, người có thẩm quyền"}, "correct": "D"}, {"id": 20, "q": "Đâu là nguyên tắc quy định thủ tục hành chính?", "options": {"A": "Đề cao trách nhiệm của cán bộ, công chức trong giải quyết công việc cho cá nhân, tổ chức", "B": "Đảm bảo tính hợp hiến, hợp pháp, thống nhất, đồng bộ, hiệu quả của các quy định về thủ tục hành chính", "C": "Bảo đảm quyền được phản ánh, kiến nghị của các cá nhân, tổ chức đối với các thủ tục hành chính", "D": "Bảo đảm khách quan, công bằng trong thực hiện thủ tục hành chính"}, "correct": "B"}]}, {"id": 11, "title": "Đề 11", "count": 9, "duration_minutes": 15, "questions": [{"id": 83, "q": "Theo nghị định 63/2010/ND- CP của Chính phủ đã được  sửa đổi ,bổ sung, phương án nào dưới đây là trách nhiệm của cơ quan thực hiện TTHC", "options": {"A": "Thực hiện sự công tâm trong  giải quyết TTHC", "B": "Bảo đảm TTHC ngắn gọn, hợp lý", "C": "Bảo đảm TTHC đơn giản dễ hiểu", "D": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định"}, "correct": "D"}, {"id": 7, "q": "Đặc điểm của thủ tục hành chính là?", "options": {"A": "Thủ tục hành chính có sự linh hoạt theo yêu cầu triển khai pháp luật vào đời sống,Thủ tục hành chính có tính đa dạng, phức tạp.", "B": "Thủ tục hành chính được thực hiện một cách thống nhất,Thủ tục hành chính do cơ quan nhà nước, người có thẩm quyền quy định.", "C": "Thủ tục hành chính là quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế.", "D": "Tất cả đáp án trên"}, "correct": "D"}, {"id": 95, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung phương án nào dưới đây là nội dung trong một quyết định công bố TTHC mới ban hành", "options": {"A": "Thời gian thực hiện TTHC", "B": "Địa điểm TTHC", "C": "Các bộ phận tạo thành TTHC theo quy định", "D": "Không gian thực hiện TTHC"}, "correct": "A"}, {"id": 58, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính", "B": "Giám sát việc thực hiện thủ tục hành chính; phản ánh, kiến nghị với cơ quan nhà nước, người có thẩm quyền về những bất hợp lý của thủ tục hành chính và các hành vi vi phạm của cán bộ, công chức trong thực hiện thủ tục hành chính", "C": "Hỗ trợ người có công, người cao tuổi, người tàn tật, người nghèo, phụ nữ mang thai, trẻ mồ côi và người thuộc diện bảo trợ xã hội khác trong thực hiện thủ tục hành chính", "D": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố"}, "correct": "B"}, {"id": 48, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Sử dụng, bố trí cán bộ, công chức có phẩm chất đạo đức tốt, văn hóa giao tiếp chuẩn mực, đủ trình độ về chuyên môn, nghiệp vụ và năng lực phù hợp để thực hiện thủ tục hành chính", "B": "Phối hợp và chia sẻ thông tin trong quá trình giải quyết công việc của cá nhân, tổ chức", "C": "Tiếp nhận và giải quyết hồ sơ của cá nhân, tổ chức theo quy định.", "D": "Cấp giấy biên nhận hồ sơ, tài liệu theo quy định."}, "correct": "C"}, {"id": 67, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân.", "B": "bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "C": "bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "D": "Công tác kiểm soát thủ tục hành chính góp phần tháo gỡ những  khó khăn, vướng mắc trong quá trình thực thi công vụ của cán bộ, công chức, giảm phiền hà cho nhân dân."}, "correct": "D"}, {"id": 36, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "B": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "C": "Cấp giấy biên nhận hồ sơ, tài liệu theo quy định", "D": "Chủ động tham mưu, đề xuất, sáng kiến cải tiến việc thực hiện thủ tục hành chính; kịp thời phát hiện, kiến nghị với cơ quan, người có thẩm quyền để sửa đổi, bổ sung, thay đổi hoặc hủy bỏ, bãi bỏ các quy định về thủ tục hành chính không phù hợp, thiếu khả thi"}, "correct": "C"}, {"id": 107, "q": "Đăng ký sự kiện hộ tịch khai sinh cho công dân VN cư trú ở trong nước thuộc thẩm quyền của cơ quan nào trong các phương án dưới đây?", "options": {"A": "Chủ tịch ubnd xã", "B": "Ubnd xã", "C": "Sở Tư pháp", "D": "UBND cấp tỉnh"}, "correct": "B"}, {"id": 8, "q": "Đâu là ý nghĩa của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "B": "Thủ tục hành chính được thực hiện một cách thống nhất", "C": "Thủ tục hành chính là quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế", "D": "Thủ tục hành chính do cơ quan nhà nước, người có thẩm quyền quy định"}, "correct": "A"}]}, {"id": 12, "title": "Đề 12", "count": 9, "duration_minutes": 15, "questions": [{"id": 96, "q": "Theo Nghị định 63/2010/ND- CP của Chính Phủ đã được  sửa đổi ,bổ sung , nguyên tắc “ Đơn giản dễ hiểu và thực hiện” thuộc nguyên tắc nào dưới đây?", "options": {"A": "NT rà soát, đánh giá TTHC", "B": "NT quy định TTHC", "C": "NT kiểm soát TTHC", "D": "NT thực hiện TTHC"}, "correct": "B"}, {"id": 108, "q": "Phương án nào dưới đây là đối tượng thực hiện thủ tục “ dk kết hôn có yếu tố nước ngoài”", "options": {"A": "người VN định cư ở nước ngoài, người nước ngoài sinh sống tại Vn", "B": "Người nước ngoài sinh sống tại VN", "C": "Công dân vn, người Việt Nam định cư ở nước ngoài", "D": "Cá nhân, tổ chức"}, "correct": "A"}, {"id": 69, "q": "Ý nghĩa của kiểm soát thủ tục hành chính là?", "options": {"A": "bảo đảm cho hoạt động quản lý hành chính nhà nước được thống nhất", "B": "Kiểm soát thủ tục hành chính có ý nghĩa lớn trong việc nâng cao chất lượng thủ tục hành chính được xây dựng và ban hành.", "C": "bảo đảm cho các quy phạm nội dung của pháp luật được thực hiện", "D": "tạo ra cơ sở và điều kiện thuận lợi giúp các cơ quan nhà nước xử lý các công việc của nhân dân theo luật định, bảo vệ quyền, lợi ích chính đáng của các tổ chức và cá nhân."}, "correct": "B"}, {"id": 84, "q": "Theo nghị định 63/2010/ND- CP của Chính phủ đã được  sửa đổi ,bổ sung,” tiếp nhận, xử lý các phản ánh, kiến nghị của cá nhân ,tổ chức trong thực hiện TTHC là trách nhiệm của cơ quan hay cá nhân", "options": {"A": "cơ quan quy định  TTHC", "B": "Cán bộ, công chức được phân công thực hiện TTHC", "C": "Cơ quan thực hiện TTHC", "D": "Người đứng đầu bộ, cơ quan ngang bộ, UBND tỉnh, thành phố trực thuộc Trung ương"}, "correct": "C"}, {"id": 10, "q": "Đâu là ý nghĩa của thủ tục hành chính?", "options": {"A": "Thủ tục hành chính do cơ quan nhà nước, người có thẩm quyền quy định", "B": "Thủ tục hành chính là quy phạm có tính thủ tục để đưa pháp luật vào đời sống thực tế", "C": "Thủ tục hành chính là là một bộ phận của pháp luật về hành chính nên việc xây dựng và thực hiện tốt thủ tục hành chính có ý nghĩa rất lớn đối với quá trình xây dựng và triển khai pháp luật", "D": "Thủ tục hành chính có sự linh hoạt theo yêu cầu triển khai pháp luật vào đời sống"}, "correct": "C"}, {"id": 64, "q": "Nguyên tắc kiểm soát thủ tục hành chính là?", "options": {"A": "Kiểm soát thủ tục hành chính phải bảo đảm thực hiện có hiệu quả mục tiêu cải cách thủ tục hành chính", "B": "cải cách hành chính; bảo đảm điều phối, huy động sự tham gia tích cực, rộng rãi", "C": "của tất cả các cơ quan, tổ chức, cá nhân vào quá trình kiểm soát thủ tục hành chính\"", "D": "cả a,b,c"}, "correct": "D"}, {"id": 52, "q": "Đâu là trách nhiệm của cán bộ, công chức được phân công thực hiện thủ tục hành chính?", "options": {"A": "Thực hiện cơ chế một cửa, một cửa liên thông trong thực hiện thủ tục hành chính", "B": "Tiếp nhận, xử lý các phản ánh, kiến nghị của cá nhân, tổ chức trong thực hiện thủ tục hành chính", "C": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "D": "Ứng dụng công nghệ thông tin và các tiến bộ khoa học kỹ thuật trong thực hiện thủ tục hành chính"}, "correct": "C"}, {"id": 39, "q": "Đâu là trách nhiệm thực hiện thủ tục hành chính của cơ quan nhà nước?", "options": {"A": "Chấp hành nghiêm túc các quy định của cấp có thẩm quyền về thủ tục hành chính đã được người đứng đầu Bộ, cơ quan ngang Bộ, Ủy ban nhân dân tỉnh, thành phố trực thuộc Trung ương công bố", "B": "Không tự đặt ra thủ tục hành chính, hồ sơ, giấy tờ ngoài quy định của pháp luật", "C": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "D": "Phải tạo thuận lợi cho đối tượng thực hiện thủ tục hành chính; có tác phong, thái độ lịch sự, nghiêm túc, khiêm tốn; ngôn ngữ giao tiếp phải chuẩn mực, rõ ràng, mạch lạc trong thực hiện thủ tục hành chính."}, "correct": "D"}, {"id": 60, "q": "Đâu là quyền và nghĩa vụ của đối tượng thực hiện thủ tục hành chính?", "options": {"A": "Thực hiện cơ chế một cửa, một cửa liên thông trong thực hiện thủ tục hành chính", "B": "Nêu rõ lý do bằng văn bản trong trường hợp từ chối thực hiện hoặc có yêu cầu bổ sung giấy tờ trong thời hạn giải quyết theo quy định", "C": "Phối hợp với các cơ quan, tổ chức có liên quan trong việc thực hiện thủ tục hành chính", "D": "Trực tiếp hoặc uỷ quyền cho người đại diện hợp pháp của mình tham gia thực hiện thủ tục hành chính theo quy định của pháp luật"}, "correct": "D"}]}, {"id": 13, "title": "Đề 13", "count": 40, "duration_minutes": 45, "questions": [{"id": 159, "q": "Ngày 10/08/2022, Ủy ban nhân dân quận X (thành phố Y) ban hành quyết định thu hồi 100m2 đất của ông Trần Văn T. Không đồng ý với quyết định này, ông T khiếu nại. Sau khi nhận được quyết định giải quyết khiếu nại, không đồng ý ông tiếp tục khiếu nại lần 2. Ông T muốn biết thời hạn giải quyết khiếu nại lần hai là bao lâu (biết rằng đây không phải vụ việc phức tạp)?", "options": {"A": "Không quá 15 ngày, kể từ ngày thụ lý", "B": "Không quá 30 ngày, kể từ ngày thụ lý", "C": "Không quá 45 ngày, kể từ ngày thụ lý", "D": "Không quá 60 ngày, kể từ ngày thụ lý"}, "correct": "C"}, {"id": 172, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), khẳng định nào sau đây không phải là hình thức xử phạt vi phạm hành chính:", "options": {"A": "Bồi thường thiệt hại", "B": "Cảnh cáo", "C": "Phạt tiền", "D": "Trục xuất"}, "correct": "A"}, {"id": 115, "q": "Khẳng định nào sau đây đúng?", "options": {"A": "Quyết định chủ đạo được ban hành để giải quyết một công việc cụ thể trên từng lĩnh vực của quản lý hành chính nhà nước", "B": "Quyết định chủ đạo nhằm cụ thể hóa Luật, Pháp lệnh, đưa ra quy tắc xử sự xác định các quyền và nghĩa vụ cho các đối tượng liên quan.", "C": "Quyết định chủ đạo ban hành nhằm mục đích đưa ra đường lối, chủ trương, chính sách, những giải pháp lớn về quản lý hành chính nhà nước", "D": "Quyết định chủ đạo được áp dụng một lần, cho một hoặc một số đối tượng nhất định"}, "correct": "C"}, {"id": 208, "q": "Ngày 01/10/2022, anh Nguyễn Văn X (có năng lực trách nhiệm hành chính) đã có hành vi vượt đèn đỏ trong quá trình tham gia giao thông tại phường A, quận B, thành phố C. Anh X sẽ không bị xử phạt vi phạm hành chính trong những trường hợp nào sau đây?", "options": {"A": "Thực hiện hành vi vi phạm hành chính trong tình thế cấp thiết", "B": "Thực hiện hành vi vi phạm hành chính do phòng vệ chính đáng", "C": "Thực hiện hành vi vi phạm hành chính do sự kiện bất ngờ", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 211, "q": "Anh Nguyễn Văn A là nhân viên kinh doanh tại doanh nghiệp X. Tháng 11/2023, Anh A xin nghỉ việc để giải quyết việc gia đình, doanh nghiệp X đã trừ ½ tiền lương của anh, A không đồng ý, anh A và Giám đốc doanh nghiệp X xảy ra mâu thuẫn. Trong quá trình giải quyết mâu thuẫn, anh A dùng vũ lực đánh Giám đốc doanh nghiệp X. Theo kết luận giám định, Giám đốc doanh nghiệp X bị suy giảm sức khỏe 7%. Anh/chị hãy xác định vi phạm pháp luật của anh A (biết rằng hành vi lần đầu thực hiện)?", "options": {"A": "Vi phạm hình sự", "B": "Vi phạm hành chính", "C": "Vi phạm dân sự", "D": "Vi phạm kỷ luật"}, "correct": "B"}, {"id": 204, "q": "Ngày 01/8/2023, em Nguyễn Văn M, 12 tuổi (có khả năng nhận thức) có hành vi vượt đèn đỏ trong quá trình tham gia giao thông tại phường L, quận P, thành phố Q. Vậy em M có phải chịu trách nhiệm hành chính không?", "options": {"A": "Có", "B": "Không", "C": "Được áp dụng tình tiết giảm nhẹ", "D": "Bị áp dụng tình tiết tăng nặng"}, "correct": "B"}, {"id": 194, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), trường hợp nào sau đây không phải biện pháp xử lý hành chính?", "options": {"A": "Biện pháp giáo dục tại xã, phường, thị trấn", "B": "Biện pháp đưa vào trường giáo dưỡng", "C": "Biện pháp đưa vào cơ sở giáo dục bắt buộc", "D": "Tịch thu tang vật, phương tiện vi phạm"}, "correct": "D"}, {"id": 132, "q": "Trường hợp nào sau đây không phải chủ thể thực hiện thủ tục hành chính?", "options": {"A": "Cơ quan nhà nước", "B": "Cán bộ, công chức nhà nước", "C": "Tất cả các tổ chức", "D": "Cá nhân được Nhà nước trao quyền quản lý trong trường hợp cụ thể do pháp luật quy định"}, "correct": "C"}, {"id": 202, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), \"Sự kiện xảy ra một cách khách quan không thể lường trước được và không thể khắc phục được mặc dù đã áp dụng mọi biện pháp cần thiết và khả năng cho phép\" được gọi là:", "options": {"A": "Sự kiện bất ngờ", "B": "Sự kiện bất khả kháng", "C": "Tình thế cấp thiết", "D": "Sự kiện pháp lý"}, "correct": "B"}, {"id": 200, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), \"Sự kiện mà cá nhân, tổ chức không thể thấy trước hoặc không buộc phải thấy trước hậu quả của hành vi nguy hại cho xã hội do mình gây ra\" được gọi là:", "options": {"A": "Sự kiện bất ngờ", "B": "Sự kiện bất khả kháng", "C": "Tình thế cấp thiết", "D": "Sự kiện pháp lý"}, "correct": "A"}, {"id": 179, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), người từ đủ 14 tuổi đến dưới 16 tuổi bị xử phạt vi phạm hành chính trong trường hợp nào sau đây?", "options": {"A": "Vi phạm hành chính do cố ý", "B": "Vi phạm hành chính do vô ý", "C": "Mọi vi phạm hành chính", "D": "Chưa đủ tuổi xử phạt"}, "correct": "A"}, {"id": 155, "q": "Ngày 02/08/2022, Ủy ban nhân dân huyện X ban hành quyết định thu hồi 300m2 đất của bà Hoàng Thị A. Cho rằng quyền và lợi ích bị xâm phạm, bà A khiếu nại. Đối tượng khiếu nại trong trường hợp này là gì?", "options": {"A": "Quyết định hành chính", "B": "Quyết định kỷ luật", "C": "Hành vi hành chính", "D": "Quyết định tư pháp"}, "correct": "A"}, {"id": 215, "q": "Ngày 21/8/2023, Nguyễn Văn A (học sinh lớp 8, trường THPT B), đã thực hiện hành vi điều khiển xe máy vượt đèn đỏ. A thắc mắc không biết mình đã đủ tuổi xử phạt vi phạm hành chính hay chưa? Anh/Chị hãy cho biết độ tuổi xử phạt vi phạm hành chính là bao nhiêu?", "options": {"A": "Từ đủ 12 tuổi trở lên", "B": "Từ đủ 13 tuổi trở lên", "C": "Từ đủ 14 tuổi trở lên", "D": "Từ đủ 15 tuổi trở lên"}, "correct": "C"}, {"id": 218, "q": "Ngày 21/9/2023, anh Nguyễn Văn A, thực hiện hành vi vi phạm hành chính và bị cơ quan có thẩm quyền ra quyết định xử phạt với hình thức phạt tiền (cụ thể 150.000 đồng). Với mức phạt này anh A sẽ bị áp dụng thủ tục xử phạt nào sau đây (biết rằng vi phạm hành chính này không cần sử dụng phương tiện, thiết bị kỹ thuật, nghiệp vụ để phát hiện)?", "options": {"A": "Xử phạt vi phạm hành chính không lập biên bản", "B": "Xử phạt vi phạm hành chính lập biên bản", "C": "Xác minh sau đó 07 ngày sẽ ban hành quyết định xử phạt vi phạm hành chính", "D": "Xác minh sau đó 10 ngày sẽ ban hành quyết định xử phạt vi phạm hành chính"}, "correct": "A"}, {"id": 209, "q": "Anh Nguyễn Văn A (15 tuổi, có năng lực trách nhiệm hành chính, trú tại xã B, huyện C, tỉnh D), từ 02/02/2023 đến 02/8/2023 anh A đã 2 lần bị xử phạt vi phạm hành chính và bị lập biên bản vi phạm hành chính tại lần vi phạm thứ ba về hành vi gây rối trật tự công cộng. Với hành vi này, anh A bị áp dụng biện pháp đưa vào trường giáo dưỡng (do trước đó A đã bị áp dụng biện pháp giáo dục tại xã, phường, thị trấn). Anh/chị hãy cho biết chủ thể nào có thẩm quyền quyết định áp dụng biện pháp này?", "options": {"A": "Chủ tịch Ủy ban nhân dân xã B", "B": "Chủ tịch Ủy ban nhân dân huyện C", "C": "Tòa án nhân dân huyện C", "D": "Tòa án nhân dân tỉnh D"}, "correct": "C"}, {"id": 137, "q": "Thủ tục hành chính bao gồm:", "options": {"A": "Thủ tục ban hành văn bản quy phạm pháp luật", "B": "Thủ tục giải quyết công việc cụ thể", "C": "Thủ tục hành chính nội bộ", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 185, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), chủ thể nào có thẩm quyền quyết định áp dụng biện pháp đưa vào cơ sở giáo dục bắt buộc?", "options": {"A": "Chủ tịch Ủy ban nhân dân cấp xã", "B": "Chủ tịch Ủy ban nhân dân cấp huyện", "C": "Viện kiểm sát nhân dân cấp huyện", "D": "Tòa án nhân dân cấp huyện"}, "correct": "D"}, {"id": 197, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), những hành vi bị nghiêm cấm bao gồm:", "options": {"A": "Giữ lại vụ vi phạm có dấu hiệu tội phạm để xử lý vi phạm hành chính.", "B": "Can thiệp trái pháp luật vào việc xử lý vi phạm hành chính.", "C": "Kéo dài thời hạn áp dụng biện pháp xử lý hành chính.", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 174, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), các biện pháp khắc phục hậu quả bao gồm:", "options": {"A": "Buộc cải chính thông tin sai sự thật hoặc gây nhầm lẫn", "B": "Buộc loại bỏ yếu tố vi phạm trên hàng hóa, bao bì hàng hóa, phương tiện kinh doanh, vật phẩm", "C": "Buộc thu hồi sản phẩm, hàng hóa không bảo đảm chất lượng", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 147, "q": "Trường hợp nào sau đây không phải quyết định hành chính?", "options": {"A": "Nghị định số 138/2020/NĐ-CP ngày 27 tháng 11 năm 2020 của Chính phủ quy định về tuyển dụng, sử dụng và quản lý công chức", "B": "Quyết định số 08/2022/QĐXXST-HC của Tòa án nhân dân tỉnh X về việc đưa vụ án ra xét xử sơ thẩm", "C": "Quyết định số 342/QĐ-UBND của Ủy ban nhân dân huyện Y về việc cấp giấy chứng nhận quyền sử dụng đất cho hộ gia đình nhà bà A", "D": "Quyết định số 124/QĐ-UBND của Ủy ban nhân dân huyện A về việc thu hồi 100m2 đất của ông Nguyễn Văn M"}, "correct": "B"}, {"id": 130, "q": "Yêu cầu về tính hợp lý của quyết định hành chính bao gồm:", "options": {"A": "Bảo đảm lợi ích của Nhà nước và nguyện vọng của nhân dân", "B": "Quyết định hành chính phải có tính dự báo, tính khả thi", "C": "Ngôn ngữ phải rõ ràng, dễ hiểu, các thuật ngữ pháp lý phải chính xác, không được đa nghĩa", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 214, "q": "Ngày 20/5/2023, bà Nguyễn Thị A (trú tại xã B, huyện C, tỉnh D) có hành vi xây dựng nhà ở trái phép. Sau đó, Chủ tịch Ủy ban nhân dân huyện C ra quyết định xử phạt vi phạm hành chính với hình thức phạt tiền và áp dụng biện pháp khắc phục hậu quả yêu cầu bà A phá dỡ công trình xây dựng trái phép. Hỏi chủ thể nào có trách nhiệm theo dõi, đôn đốc và kiểm tra việc thi hành biện pháp khắc phục hậu quả do bà A thực hiện?", "options": {"A": "Chủ tịch Ủy ban nhân dân xã B", "B": "Chủ tịch Ủy ban nhân dân huyện C", "C": "Chủ tịch Ủy ban nhân dân tỉnh D", "D": "Bộ trưởng Bộ Xây dựng"}, "correct": "B"}, {"id": 134, "q": "Chủ thể tham gia thủ tục hành chính là gì?", "options": {"A": "Chủ thể sử dụng quyền lực nhà nước, nhân danh Nhà nước tiến hành các thủ tục hành chính", "B": "Chủ thể phục tùng quyền lực nhà nước khi tham gia thủ tục hành chính", "C": "Chủ thể giải quyết các thủ tục hành chính", "D": "Mọi chủ thể của thủ tục hành chính"}, "correct": "B"}, {"id": 210, "q": "Ngày 15/12/2022, anh Hà Văn M là sĩ quan của bộ đội biên phòng đồn X, tỉnh Y có hành vi vượt đèn đỏ khi tham gia giao thông. Vậy anh M là bộ đội có bị xử lý vi phạm hành chính không?", "options": {"A": "Bị xử lý vi phạm hành chính như đối với công dân khác", "B": "Không bị xử lý vi phạm hành chính", "C": "Được áp dụng tình tiết giảm nhẹ", "D": "Bị áp dụng tình tiết tăng nặng"}, "correct": "A"}, {"id": 135, "q": "Căn cứ vào mục đích của thủ tục, thủ tục hành chính được chia thành:", "options": {"A": "Thủ tục hành chính nội bộ và thủ tục hành chính liên hệ", "B": "Thủ tục hành chính nội bộ và thủ tục ban hành văn bản quy phạm pháp luật", "C": "Thủ tục ban hành văn bản quy phạm pháp luật và thủ tục giải quyết các công việc cụ thể", "D": "Thủ tục hành chính liên hệ và thủ tục ban hành văn bản quy phạm pháp luật"}, "correct": "C"}, {"id": 133, "q": "Chủ thể thực hiện thủ tục hành chính là gì?", "options": {"A": "Chủ thể sử dụng quyền lực nhà nước, nhân danh Nhà nước tiến hành các thủ tục hành chính", "B": "Chủ thể phục tùng quyền lực nhà nước khi tham gia thủ tục hành chính", "C": "Chủ thể giải quyết các thủ tục hành chính", "D": "Mọi chủ thể của thủ tục hành chính"}, "correct": "A"}, {"id": 160, "q": "Ngày 22/10/2022, Ủy ban nhân dân huyện X ban hành quyết định thu hồi 200m2 đất của ông Trần Văn M. Không đồng ý, ông M muốn khiếu nại nhưng không biết khiếu nại bằng hình thức nào. Anh/chị hãy tư vấn.", "options": {"A": "Chỉ có thể khiếu nại bằng đơn", "B": "Chỉ có thể đến cơ quan có thẩm quyền khiếu nại trực tiếp", "C": "Khiếu nại bằng đơn khiếu nại hoặc khiếu nại trực tiếp.", "D": "Gửi email đến cơ quan có thẩm quyền"}, "correct": "C"}, {"id": 164, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), cá nhân, tổ chức muốn chứng minh mình không vi phạm hành chính thì có thể thực hiện bằng cách nào?", "options": {"A": "Chỉ có thể tự mình chứng minh", "B": "Chỉ có thể thông qua người đại diện hợp pháp", "C": "Không được phép chứng minh", "D": "Tự mình hoặc có thể thông qua người đại diện hợp pháp"}, "correct": "D"}, {"id": 193, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), trường hợp nào sau đây không phải biện pháp khắc phục hậu quả?", "options": {"A": "Quản lý người nước ngoài vi phạm pháp luật Việt Nam trong thời gian làm thủ tục trục xuất", "B": "Buộc cải chính thông tin sai sự thật hoặc gây nhầm lẫn", "C": "Buộc thu hồi sản phẩm, hàng hóa không bảo đảm chất lượng", "D": "Buộc thực hiện biện pháp khắc phục tình trạng ô nhiễm môi trường, lây lan dịch bệnh"}, "correct": "A"}, {"id": 117, "q": "Theo quy định của Luật Khiếu nại năm 2011, trường hợp nào sau đây không phải đối tượng khiếu nại hành chính?", "options": {"A": "Quyết định hành chính", "B": "Quyết định kỷ luật cán bộ, công chức", "C": "Quyết định tư pháp", "D": "Hành vi hành chính"}, "correct": "C"}, {"id": 220, "q": "Ngày 04/5/2023, Nguyễn Văn A thực hiện hành vi vi phạm hành chính và bị cơ quan có thẩm quyền ra quyết định xử phạt với hình thức cảnh cáo. Với mức phạt này, A sẽ bị áp dụng thủ tục xử phạt nào sau đây (biết rằng vi phạm hành chính này không cần sử dụng phương tiện, thiết bị kỹ thuật, nghiệp vụ để phát hiện)?", "options": {"A": "Xử phạt vi phạm hành chính không lập biên bản", "B": "Xử phạt vi phạm hành chính lập biên bản", "C": "Xác minh sau đó 07 ngày sẽ ban hành quyết định xử phạt vi phạm hành chính", "D": "Xác minh sau đó 10 ngày sẽ ban hành quyết định xử phạt vi phạm hành chính"}, "correct": "A"}, {"id": 201, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), \"Việc cá nhân, tổ chức đã bị ra quyết định xử phạt vi phạm hành chính nhưng chưa hết thời hạn được coi là chưa bị xử phạt vi phạm hành chính mà lại thực hiện hành vi vi phạm hành chính đã bị xử phạt; cá nhân đã bị ra quyết định áp dụng biện pháp xử lý hành chính nhưng chưa hết thời hạn được coi là chưa bị áp dụng biện pháp xử lý hành chính mà lại thực hiện hành vi thuộc đối tượng bị áp dụng biện pháp xử lý hành chính đó\" được gọi là:", "options": {"A": "Vi phạm hành chính nhiều lần", "B": "Tái phạm", "C": "Vi phạm hành chính có tổ chức", "D": "Tái phạm và vi phạm hành chính nhiều lần"}, "correct": "B"}, {"id": 119, "q": "Quyết định hành chính quy phạm là gì?", "options": {"A": "Có nội dung là những quy tắc xử sự, xác định các quyền và nghĩa vụ cho các đối tượng liên quan, quyết định quy phạm tạo ra một khuôn khổ pháp lý, trong đó các chủ thể sẽ thực hiện quyền và nghĩa vụ của mình.", "B": "Đưa ra những chủ trương, chính sách, giải pháp lớn về quản lý hành chính nhà nước", "C": "Ban hành nhằm mục đích giải quyết công việc cụ thể trên từng lĩnh vực của quản lý hành chính nhà nước", "D": "Quyết định chỉ được áp dụng một lần"}, "correct": "A"}, {"id": 176, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), biện pháp xử lý hành chính áp dụng đối với trường hợp nào sau đây?", "options": {"A": "Cá nhân vi phạm pháp luật về an ninh, trật tự, an toàn xã hội mà không phải là tội phạm", "B": "Tổ chức vi phạm pháp luật về an ninh, trật tự, an toàn xã hội mà không phải là tội phạm", "C": "Cá nhân và tổ chức vi phạm pháp luật về an ninh, trật tự, an toàn xã hội mà không phải là tội phạm", "D": "Cá nhân vi phạm pháp luật trong mọi lĩnh vực mà không phải là tội phạm"}, "correct": "A"}, {"id": 121, "q": "Yêu cầu về tính hợp pháp của quyết định hành chính bao gồm:", "options": {"A": "Ban hành đúng thẩm quyền", "B": "Nội dung không trái với Hiến pháp và luật", "C": "Ban hành đúng trình tự, thủ tục và hình thức do pháp luật quy định", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 199, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), người từ đủ 16 tuổi trở lên bị xử phạt vi phạm hành chính trong trường hợp nào sau đây?", "options": {"A": "Chỉ áp dụng với vi phạm hành chính do cố ý", "B": "Chỉ áp dụng với vi phạm hành chính do vô ý", "C": "Mọi vi phạm hành chính", "D": "Chưa đủ tuổi xử phạt"}, "correct": "C"}, {"id": 154, "q": "Ngày 15/7/2022, Chủ tịch Ủy ban nhân dân huyện X thực hiện việc cưỡng chế thu hồi 100m2 đất của ông Nguyễn Văn A. Không đồng ý, ông A có thể làm gì để bảo vệ quyền và lợi ích hợp pháp của mình?", "options": {"A": "Khiếu nại quyết định hành chính hoặc khởi kiện vụ án hành chính", "B": "Khiếu nại hành vi hành chính hoặc khởi kiện vụ án hành chính", "C": "Tố cáo", "D": "Làm đơn kiến nghị, phản ánh"}, "correct": "B"}, {"id": 216, "q": "Ngày 29/10/2023, anh Nguyễn Văn A, thực hiện hành vi vi phạm hành chính và bị cơ quan có thẩm quyền ra quyết định xử phạt với hình thức phạt tiền (cụ thể 800.000 đồng). Với mức phạt này anh A sẽ bị áp dụng thủ tục xử phạt nào sau đây?", "options": {"A": "Xử phạt vi phạm hành chính không lập biên bản", "B": "Xử phạt vi phạm hành chính lập biên bản", "C": "Ban hành quyết định xử phạt tại chỗ", "D": "Nộp phạt tại chỗ"}, "correct": "B"}, {"id": 213, "q": "Ngày 20/5/2023, bà Nguyễn Thị A (trú tại xã B, huyện C, tỉnh D) có hành vi xây dựng nhà ở trái phép. Sau đó, cơ quan có thẩm quyền ra quyết định xử phạt vi phạm hành chính với hình thức phạt tiền và áp dụng biện pháp khắc phục hậu quả yêu cầu bà A phá dỡ công trình xây dựng trái phép. Hỏi chi phí cho việc thực hiện biện pháp khắc phục hậu quả đó do chủ thể nào chi trả?", "options": {"A": "Bà Nguyễn Thị A", "B": "Chủ tịch Ủy ban nhân dân xã B", "C": "Chủ tịch Ủy ban nhân dân huyện C", "D": "Chủ tịch Ủy ban nhân dân tỉnh D"}, "correct": "A"}, {"id": 162, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), biện pháp xử lý hành chính bao gồm:", "options": {"A": "Đưa vào trường giáo dưỡng", "B": "Giáo dục tại xã, phường, thị trấn", "C": "Đưa vào cơ sở giáo dục bắt buộc và đưa vào cơ sở cai nghiện bắt buộc", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}]}, {"id": 14, "title": "Đề 14", "count": 40, "duration_minutes": 45, "questions": [{"id": 203, "q": "Ngày 01/3/2023, anh Nguyễn Văn H, là công an Quận X (tỉnh Y), có hành vi không đội mũ bảo hiểm trong quá trình tham gia giao thông. Vậy anh H là công an có bị xử lý vi phạm hành chính không?", "options": {"A": "Bị xử lý vi phạm hành chính như đối với công dân khác", "B": "Không bị xử lý vi phạm hành chính", "C": "Được áp dụng tình tiết giảm nhẹ", "D": "Bị áp dụng tình tiết tăng nặng"}, "correct": "A"}, {"id": 180, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), các hình thức xử phạt vi phạm hành chính bao gồm:", "options": {"A": "Tước quyền sử dụng giấy phép, chứng chỉ hành nghề có thời hạn hoặc đình chỉ hoạt động có thời hạn.", "B": "Tịch thu tang vật vi phạm hành chính, phương tiện được sử dụng để vi phạm hành chính (sau đây gọi chung là tang vật, phương tiện vi phạm hành chính).", "C": "Trục xuất.", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 212, "q": "Ông Nguyễn Văn C là Chủ tịch Uỷ ban nhân dân huyện Y, tỉnh M. Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), ông C có thẩm quyền xử lý vi phạm hành chính với các hình thức xử phạt nào sau đây?", "options": {"A": "Phạt cảnh cáo", "B": "Áp dụng biện pháp khắc phục hậu quả theo quy định của pháp luật", "C": "Tước quyền sử dụng giấy phép, chứng chỉ hành nghề có thời hạn hoặc đình chỉ hoạt động có thời hạn", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 129, "q": "Khẳng định nào sau đây là đúng?", "options": {"A": "Thủ tục hành chính do quy phạm pháp luật hành chính quy định", "B": "Thủ tục hành chính do quy phạm pháp luật dân sự quy định", "C": "Thủ tục hành chính do mọi quy phạm pháp luật quy định", "D": "Thủ tục hành chính do quy phạm pháp luật hình sự quy định"}, "correct": "A"}, {"id": 146, "q": "Căn cứ vào tính chất pháp lý, xác định quyết định hành chính quy phạm trong các trường hợp sau:", "options": {"A": "Nghị định số 112/2020/NĐ-CP ngày 18 tháng 9 năm 2020 của Chính phủ về xử lý kỷ luật cán bộ, công chức, viên chức", "B": "Quyết định số 342/QĐ-UBND của Ủy ban nhân dân huyện Y về việc cấp giấy chứng nhận quyền sử dụng đất cho hộ gia đình nhà bà A", "C": "Quyết định số 242/QĐ-UBND của Ủy ban nhân dân huyện X về việc thu hồi đất để xây dựng công trình làm được quốc lộ", "D": "Bản án số 158/2020/HC-PT của Tòa án nhân dân tỉnh X"}, "correct": "A"}, {"id": 168, "q": "Xác định dấu hiệu của vi phạm pháp luật hành chính?", "options": {"A": "Là suy nghĩ của cá nhân, tổ chức về vi phạm", "B": "Hành vi có lỗi", "C": "Bị coi là tội phạm", "D": "Xử phạt vi phạm dân sự"}, "correct": "B"}, {"id": 165, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), hình thức xử phạt hành chính nào sau đây không áp dụng đối với công dân Việt Nam?", "options": {"A": "Phạt tiền", "B": "Tước quyền sử dụng giấy phép, chứng chỉ hành nghề có thời hạn", "C": "Tịch thu tang vật, phương tiện vi phạm", "D": "Trục xuất"}, "correct": "D"}, {"id": 151, "q": "Chị Hà Thị H là công chức phòng Tư pháp (Ủy ban nhân dân huyện A, tỉnh B). Ngày 20/8/2022, chị H đã có hành vi gây mất đoàn kết trong cơ quan, tổ chức và bị xử lý kỷ luật. Hỏi thủ tục xử lý kỷ luật đối với chị H thuộc loại thủ tục nào?", "options": {"A": "Thủ tục ban hành văn bản quy phạm pháp luật", "B": "Thủ tục hành chính nội bộ", "C": "Thủ tục hành chính liên hệ", "D": "Thủ tục tư pháp"}, "correct": "B"}, {"id": 187, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), xử phạt vi phạm hành chính không lập biên bản được áp dụng trong trường hợp nào sau đây?", "options": {"A": "Phạt tiền đến 200.000 đồng đối với cá nhân", "B": "Phạt tiền đến 250.000 đồng đối với cá nhân", "C": "Phạt tiền đến 500.000 đồng đối với cá nhân", "D": "Phạt tiền đến 750.000 đồng đối với cá nhân"}, "correct": "B"}, {"id": 190, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), không áp dụng biện pháp đưa vào trường giáo dưỡng trong các trường hợp nào sau đây?", "options": {"A": "Người không có năng lực trách nhiệm hành chính", "B": "Người đang mang thai có chứng nhận của cơ sở khám bệnh, chữa bệnh từ tuyến huyện trở lên", "C": "Phụ nữ hoặc người duy nhất đang nuôi con nhỏ dưới 36 tháng tuổi được Ủy ban nhân dân cấp xã nơi người đó cư trú xác nhận", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 196, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), trường hợp nào không thuộc tình tiết giảm nhẹ?", "options": {"A": "Vi phạm hành chính vì hoàn cảnh đặc biệt khó khăn mà không do mình gây ra", "B": "Vi phạm hành chính có tổ chức", "C": "Vi phạm hành chính do trình độ lạc hậu", "D": "Vi phạm hành chính do bị ép buộc"}, "correct": "B"}, {"id": 120, "q": "Khẳng định nào sau đây không phải yêu cầu về tính hợp pháp của quyết định hành chính?", "options": {"A": "Ban hành đúng thẩm quyền", "B": "Bảo đảm lợi ích của Nhà nước và nguyện vọng của nhân dân", "C": "Ban hành theo đúng trình tự, thủ tục và hình thức do pháp luật quy định", "D": "Nội dung không trái với Hiến pháp và luật"}, "correct": "B"}, {"id": 144, "q": "Trường hợp nào sau đây không phải quyết định hành chính?", "options": {"A": "Nghị định số 112/2020/NĐ-CP ngày 18 tháng 9 năm 2020 của Chính phủ về xử lý kỷ luật cán bộ, công chức, viên chức", "B": "Nghị quyết số 76/NQ-CP ngày 15 tháng 7 năm 2021 của Chính phủ ban hành chương trình tổng thể cải cách hành chính nhà nước giai đoạn 2021-2030", "C": "Quyết định số 242/QĐ-UBND của Ủy ban nhân dân huyện X về việc thu hồi đất để xây dựng công trình làm được quốc lộ", "D": "Bản án số 158/2020/HC-PT của Tòa án nhân dân tỉnh X"}, "correct": "D"}, {"id": 148, "q": "Ngày 02/08/2022, Ủy ban nhân dân huyện X ban hành quyết định thu hồi 200m2 đất của bà Hoàng Thị A. Không đồng ý với quyết định này, bà A khiếu nại. Sau 2 lần cơ quan có thẩm quyền giải quyết khiếu nại, bà A vẫn không đồng ý. Hỏi bà A có thể làm gì tiếp theo để bảo vệ quyền và lợi ích hợp pháp của mình?", "options": {"A": "Khiếu nại lần 3", "B": "Khởi kiện vụ án hành chính", "C": "Tố cáo", "D": "Làm đơn kiến nghị, phản ánh"}, "correct": "B"}, {"id": 182, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), chủ thể nào có thẩm quyền quyết định áp dụng biện pháp đưa vào cơ sở cai nghiện bắt buộc?", "options": {"A": "Chủ tịch Ủy ban nhân dân cấp xã", "B": "Chủ tịch Ủy ban nhân dân cấp huyện", "C": "Tòa án nhân dân cấp huyện", "D": "Viện kiểm sát nhân dân cấp huyện"}, "correct": "C"}, {"id": 138, "q": "Khẳng định nào sau đây không phải đặc điểm của thủ tục hành chính?", "options": {"A": "Là thủ tục được thực hiện bởi các chủ thể quản lý hành chính nhà nước", "B": "Thủ tục hành chính do mọi quy phạm pháp luật quy định", "C": "Thủ tục hành chính có tính mềm dẻo, linh hoạt", "D": "Thủ tục hành chính là thủ tục thực hiện hoạt động quản lý nhà nước"}, "correct": "B"}, {"id": 118, "q": "Khẳng định nào sau đây không phải đặc điểm của quyết định hành chính?", "options": {"A": "Tính dưới luật", "B": "Chỉ được ban hành bởi cơ quan hành chính nhà nước", "C": "Nội dung nhằm thực hiện hoạt động quản lý hành chính nhà nước", "D": "Tính quyền lực nhà nước"}, "correct": "B"}, {"id": 140, "q": "Thủ tục hành chính liên hệ là gì?", "options": {"A": "Thủ tục cho phép các cá nhân, tổ chức thực hiện quyền", "B": "Thủ tục tiến hành các hoạt động quản lý được thực hiện trong nội bộ cơ quan, hệ thống cơ quan hay toàn bộ bộ máy nhà nước", "C": "Thủ tục giải quyết các công việc cụ thể liên quan đến quyền, nghĩa vụ, lợi ích của tổ chức, cá nhân", "D": "Thủ tục tiến hành mọi hoạt động quản lý hành chính nhà nước"}, "correct": "C"}, {"id": 142, "q": "Thủ tục tiến hành các hoạt động quản lý, được thực hiện trong nội bộ cơ quan, hệ thống cơ quan hay toàn bộ bộ máy nhà nước, được gọi là:", "options": {"A": "Thủ tục hành chính nội bộ", "B": "Thủ tục hành chính liên hệ", "C": "Thủ tục giải quyết công việc cụ thể", "D": "Thủ tục ban hành văn bản quy phạm pháp luật"}, "correct": "A"}, {"id": 173, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), mỗi vi phạm hành chính được quy định:", "options": {"A": "Một hình thức xử phạt chính", "B": "Hai hình thức xử phạt chính", "C": "Ba hình thức xử phạt chính", "D": "Bốn hình thức xử phạt chính"}, "correct": "A"}, {"id": 136, "q": "Căn cứ vào tính chất công việc được tiến hành, thủ tục hành chính được chia thành:", "options": {"A": "Thủ tục hành chính nội bộ và thủ tục ban hành văn bản quy phạm pháp luật", "B": "Thủ tục hành chính nội bộ và thủ tục hành chính liên hệ", "C": "Thủ tục ban hành văn bản quy phạm pháp luật và thủ tục giải quyết các công việc cụ thể", "D": "Thủ tục hành chính liên hệ và thủ tục ban hành văn bản quy phạm pháp luật"}, "correct": "B"}, {"id": 205, "q": "Ngày 01/10/2022, anh Nguyễn Văn X (có năng lực trách nhiệm hành chính) đã có hành vi vượt đèn đỏ trong quá trình tham gia giao thông tại phường A, quận B, thành phố C và bị cơ quan công an ra quyết định xử phạt vi phạm hành chính. Nếu không đồng ý với quyết định xử phạt này anh X có thể làm gì để bảo vệ quyền và lợi ích hợp pháp của mình?", "options": {"A": "Khiếu nại hoặc khởi kiện", "B": "Làm đơn kiến nghị, phản ánh", "C": "Chỉ được khiếu nại", "D": "Chỉ được khởi kiện"}, "correct": "A"}, {"id": 167, "q": "Theo Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), mức phạt tiền trong xử phạt vi phạm hành chính đối với cá nhân từ:", "options": {"A": "50.000 đồng đến 1.000.000.000 đồng", "B": "100.000 đồng đến 1.000.000.000 đồng", "C": "100.000 đồng đến 2.000.000.000 đồng", "D": "100.000 đồng đến 3.000.000.000 đồng"}, "correct": "A"}, {"id": 116, "q": "Trường hợp nào sau đây là yêu cầu về tính hợp pháp của quyết định hành chính?", "options": {"A": "Bảo đảm lợi ích của Nhà nước và nguyện vọng của nhân dân", "B": "Quyết định hành chính phải có tính dự báo, tính khả thi", "C": "Ngôn ngữ phải rõ ràng, dễ hiểu, các thuật ngữ pháp lý phải chính xác, không được đa nghĩa", "D": "Nội dung không trái với Hiến pháp và luật"}, "correct": "D"}, {"id": 152, "q": "Ngày 22/10/2022, Ủy ban nhân dân huyện X ban hành quyết định thu hồi 200m2 đất của ông Trần Văn M. Không đồng ý với quyết định này, ông M khiếu nại. Hỏi thủ tục khiếu nại thuộc loại thủ tục nào?", "options": {"A": "Thủ tục ban hành văn bản quy phạm pháp luật", "B": "Thủ tục hành chính nội bộ", "C": "Thủ tục giải quyết các công việc cụ thể", "D": "Thủ tục tư pháp"}, "correct": "C"}, {"id": 131, "q": "Nguyên tắc của thủ tục hành chính bao gồm?", "options": {"A": "Nguyên tắc khách quan", "B": "Nguyên tắc công khai, minh bạch", "C": "Nguyên tắc bình đẳng trước pháp luật giữa các bên tham gia thủ tục hành chính", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 171, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), cùng một hành vi vi phạm hành chính thì mức phạt tiền đối với tổ chức bằng mấy lần mức phạt tiền đối với cá nhân?", "options": {"A": "Một lần", "B": "Hai lần", "C": "Ba lần", "D": "Bốn lần"}, "correct": "B"}, {"id": 198, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), khẳng định nào sau đây đúng?", "options": {"A": "Cảnh cáo áp dụng đối với mọi hành vi vi phạm hành chính do người chưa thành niên từ đủ 12 tuổi đến dưới 14 tuổi thực hiện", "B": "Cảnh cáo áp dụng đối với mọi hành vi vi phạm hành chính do người chưa thành niên từ đủ 13 tuổi đến dưới 15 tuổi thực hiện", "C": "Cảnh cáo áp dụng đối với mọi hành vi vi phạm hành chính do người chưa thành niên từ đủ 14 tuổi đến dưới 16 tuổi thực hiện", "D": "Cảnh cáo áp dụng đối với mọi hành vi vi phạm hành chính do người từ đủ 15 tuổi đến dưới 17 tuổi thực hiện"}, "correct": "C"}, {"id": 150, "q": "Ngày 22/10/2022, Ủy ban nhân dân huyện X ban hành quyết định thu hồi 200m2 đất của ông Trần Văn M. Nếu không đồng ý với quyết định này, ông M có thể làm gì để bảo vệ quyền và lợi ích hợp pháp của mình?", "options": {"A": "Khiếu nại hoặc khởi kiện vụ án hành chính", "B": "Chỉ được khởi kiện vụ án hành chính", "C": "Tố cáo", "D": "Làm đơn kiến nghị, phản ánh"}, "correct": "A"}, {"id": 181, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), không áp dụng biện pháp đưa vào trường giáo dưỡng đối với trường hợp nào sau đây?", "options": {"A": "Người đang mang thai có chứng nhận của cơ sở khám bệnh, chữa bệnh từ tuyến huyện trở lên.", "B": "Người từ đủ 12 tuổi đến dưới 14 tuổi thực hiện hành vi có dấu hiệu của một tội phạm đặc biệt nghiêm trọng quy định tại Bộ luật Hình sự.", "C": "Người từ đủ 14 tuổi đến dưới 16 tuổi thực hiện hành vi có dấu hiệu của một tội phạm rất nghiêm trọng hoặc một tội phạm đặc biệt nghiêm trọng quy định tại Bộ luật Hình sự.", "D": "Người từ đủ 14 tuổi đến dưới 16 tuổi thực hiện một trong các hành vi quy định và trước đó đã bị áp dụng biện pháp giáo dục tại xã, phường, thị trấn."}, "correct": "A"}, {"id": 124, "q": "Căn cứ vào tính chất pháp lý, quyết định hành chính được chia thành:", "options": {"A": "Quyết định chủ đạo và quyết định quy phạm", "B": "Quyết định quy phạm và quyết định cá biệt", "C": "Quyết định chủ đạo và quyết định cá biệt", "D": "Quyết định chủ đạo, quyết định quy phạm, quyết định cá biệt"}, "correct": "D"}, {"id": 156, "q": "Chị Hà Thị H là công chức phòng Tư pháp (Ủy ban nhân dân huyện A, tỉnh B), đã có hành vi sử dụng văn bằng, chứng chỉ giả và bị ban hành quyết định buộc thôi việc. Cho rằng hành vi của mình chưa đến mức bị buộc thôi việc, chị H có thể làm gì để bảo vệ quyền và lợi ích hợp pháp của mình?", "options": {"A": "Khiếu nại quyết định kỷ luật hoặc khởi kiện vụ án hành chính", "B": "Khiếu nại hành vi hành chính hoặc khởi kiện vụ án hành chính", "C": "Tố cáo", "D": "Làm đơn kiến nghị, phản ánh"}, "correct": "A"}, {"id": 122, "q": "Theo quy định của Luật Khiếu nại năm 2011, đối tượng khiếu nại hành chính bao gồm:", "options": {"A": "Quyết định hành chính", "B": "Hành vi hành chính", "C": "Quyết định kỷ luật cán bộ, công chức", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 217, "q": "Ngày 10/10/2023, Công ty TNHH LA (được thành lập theo đúng quy định của pháp luật), thực hiện hành vi vi phạm hành chính và bị cơ quan có thẩm quyền ra quyết định xử phạt với hình thức phạt tiền (cụ thể 1.500.000 đồng). Với mức phạt này Công ty TNHH LA sẽ bị áp dụng thủ tục xử phạt nào sau đây?", "options": {"A": "Xử phạt vi phạm hành chính không lập biên bản", "B": "Xử phạt vi phạm hành chính lập biên bản", "C": "Ban hành quyết định xử phạt tại chỗ", "D": "Nộp phạt tại chỗ"}, "correct": "B"}, {"id": 161, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), \"Hành vi có lỗi do cá nhân, tổ chức thực hiện, vi phạm quy định của pháp luật về quản lý nhà nước mà không phải là tội phạm và theo quy định của pháp luật phải bị xử phạt vi phạm hành chính\" được gọi là:", "options": {"A": "Vi phạm hành chính", "B": "Vi phạm dân sự", "C": "Vi phạm kỷ luật", "D": "Vi phạm hình sự"}, "correct": "A"}, {"id": 158, "q": "Ngày 10/08/2022, Ủy ban nhân dân quận X (thành phố Y) ban hành quyết định thu hồi 200m2 đất của ông Trần Văn T. Không đồng ý với quyết định này, ông T khiếu nại. Ông T muốn biết thời hạn giải quyết khiếu nại lần đầu là bao lâu (biết rằng đây không phải vụ việc phức tạp)?", "options": {"A": "Không quá 15 ngày, kể từ ngày thụ lý", "B": "Không quá 30 ngày, kể từ ngày thụ lý", "C": "Không quá 45 ngày, kể từ ngày thụ lý", "D": "Không quá 60 ngày, kể từ ngày thụ lý"}, "correct": "B"}, {"id": 157, "q": "Ngày 02/08/2022, Ủy ban nhân dân huyện X ban hành quyết định thu hồi 100m2 đất của bà Hoàng Thị A. Không đồng ý với quyết định này, bà A khiếu nại đơn của bà được thụ lý vào ngày 05/8/2022. Sau khi có quyết định giải quyết khiếu nại, bà A không đồng ý. Hỏi bà A có thể làm gì tiếp theo để bảo vệ quyền và lợi ích hợp pháp của mình?", "options": {"A": "Khiếu nại lần 2 hoặc khởi kiện vụ án hành chính", "B": "Chỉ có thể khởi kiện vụ án hành chính", "C": "Tố cáo", "D": "Làm đơn kiến nghị, phản ánh"}, "correct": "A"}, {"id": 145, "q": "Ngày 25/11/2022, Bà A nộp hồ sơ đề nghị Công an phường B cấp giấy tạm trú cho bà. Tuy nhiên, hết thời hạn theo quy định của pháp luật mà đề nghị cấp giấy tạm trú của bà A vẫn không được giải quyết. Bà A muốn khiếu nại để bảo vệ quyền và lợi ích hợp pháp của mình. Hỏi đối tượng khiếu nại trong trường hợp này là gì?", "options": {"A": "Quyết định hành chính", "B": "Quyết định kỷ luật", "C": "Hành vi hành chính", "D": "Quyết định tư pháp"}, "correct": "C"}, {"id": 163, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), một hành vi vi phạm hành chính chỉ bị xử phạt:", "options": {"A": "Một lần", "B": "Hai lần", "C": "Ba lần", "D": "Bốn lần"}, "correct": "A"}, {"id": 139, "q": "Thủ tục hành chính nội bộ là gì?", "options": {"A": "Thủ tục cho phép các cá nhân, tổ chức thực hiện quyền", "B": "Thủ tục tiến hành các hoạt động quản lý được thực hiện trong nội bộ cơ quan, hệ thống cơ quan hay toàn bộ bộ máy nhà nước", "C": "Thủ tục giải quyết các công việc cụ thể liên quan đến quyền, nghĩa vụ, lợi ích của tổ chức, cá nhân", "D": "Thủ tục tiến hành mọi hoạt động quản lý hành chính nhà nước"}, "correct": "B"}]}, {"id": 15, "title": "Đề 15", "count": 40, "duration_minutes": 45, "questions": [{"id": 123, "q": "Theo quy định của Luật Khiếu nại năm 2011, khi có căn cứ cho rằng quyết định hành chính là trái pháp luật, xâm phạm đến quyền và lợi ích hợp pháp của mình thì cơ quan, tổ chức, cá nhân có thể làm gì?", "options": {"A": "Tố cáo", "B": "Chỉ được khởi kiện vụ án hành chính", "C": "Khiếu nại hoặc khởi kiện vụ án hành chính", "D": "Làm đơn kiến nghị, phản ánh"}, "correct": "C"}, {"id": 177, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), hình thức phạt tiền áp dụng như thế nào?", "options": {"A": "Luôn là hình thức xử phạt chính", "B": "Luôn là hình thức xử phạt bổ sung", "C": "Vừa là hình thức xử phạt chính vừa là hình thức xử phạt bổ sung", "D": "Là hình thức xử phạt chỉ áp dụng với công dân Việt Nam"}, "correct": "A"}, {"id": 156, "q": "Chị Hà Thị H là công chức phòng Tư pháp (Ủy ban nhân dân huyện A, tỉnh B), đã có hành vi sử dụng văn bằng, chứng chỉ giả và bị ban hành quyết định buộc thôi việc. Cho rằng hành vi của mình chưa đến mức bị buộc thôi việc, chị H có thể làm gì để bảo vệ quyền và lợi ích hợp pháp của mình?", "options": {"A": "Khiếu nại quyết định kỷ luật hoặc khởi kiện vụ án hành chính", "B": "Khiếu nại hành vi hành chính hoặc khởi kiện vụ án hành chính", "C": "Tố cáo", "D": "Làm đơn kiến nghị, phản ánh"}, "correct": "A"}, {"id": 143, "q": "Xác định quyết định hành chính trong các trường hợp sau:", "options": {"A": "Luật Cán bộ công chức năm 2008", "B": "Nghị định số 100/2019/NĐ-CP ngày 30 tháng 12 năm 2019 của Chính phủ quy định xử phạt vi phạm hành chính trong lĩnh vực giao thông đường bộ và đường sắt", "C": "Quyết định đình chỉ giải quyết vụ án hành chính của Tòa án nhân dân", "D": "Bản án số 158/2020/HC-PT của Tòa án nhân dân tỉnh X"}, "correct": "B"}, {"id": 153, "q": "Chị Mai Thanh H là công chức phòng Tư pháp (Ủy ban nhân dân huyện A, tỉnh B), đã có hành vi gây mất đoàn kết trong cơ quan, tổ chức và bị Chủ tịch Ủy ban nhân dân huyện A ban hành quyết định xử lý kỷ luật với hình thức khiển trách. Không đồng ý, chị H khiếu nại. Hỏi đối tượng khiếu nại trong trường hợp này là gì?", "options": {"A": "Quyết định hành chính", "B": "Hành vi hành chính", "C": "Quyết định kỷ luật", "D": "Quyết định tư pháp"}, "correct": "C"}, {"id": 195, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), trường hợp nào không thuộc tình tiết tăng nặng?", "options": {"A": "Vi phạm hành chính có tổ chức", "B": "Vi phạm hành chính nhiều lần; tái phạm", "C": "Vi phạm hành chính do bị lệ thuộc về vật chất hoặc tinh thần", "D": "Lợi dụng chức vụ, quyền hạn để vi phạm hành chính"}, "correct": "C"}, {"id": 149, "q": "Căn cứ vào tính chất pháp lý, xác định quyết định hành chính cá biệt trong các trường hợp sau:", "options": {"A": "Nghị định số 112/2020/NĐ-CP của Chính phủ về xử lý kỷ luật cán bộ, công chức, viên chức", "B": "Nghị quyết số 76/NQ-CP của Chính phủ ban hành chương trình tổng thể cải cách hành chính nhà nước giai đoạn 2021-2030", "C": "Quyết định số 242/QĐ-UBND của Ủy ban nhân dân huyện X về việc thu hồi đất để xây dựng công trình làm được quốc lộ", "D": "Bản án số 158/2020/HC-PT của Tòa án nhân dân tỉnh X"}, "correct": "C"}, {"id": 141, "q": "Chủ thể phục tùng quyền lực nhà nước khi tham gia vào thủ tục hành chính, được gọi là:", "options": {"A": "Chủ thể thực hiện thủ tục hành chính", "B": "Chủ thể tham gia thủ tục hành chính", "C": "Chủ thể giải quyết thủ tục hành chính", "D": "Chủ thể đặc biệt"}, "correct": "B"}, {"id": 166, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), những trường hợp không xử phạt vi phạm hành chính bao gồm:", "options": {"A": "Thực hiện hành vi vi phạm hành chính do sự kiện bất khả kháng", "B": "Thực hiện hành vi vi phạm hành chính do phòng vệ chính đáng", "C": "Thực hiện hành vi vi phạm hành chính trong tình thế cấp thiết", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 138, "q": "Khẳng định nào sau đây không phải đặc điểm của thủ tục hành chính?", "options": {"A": "Là thủ tục được thực hiện bởi các chủ thể quản lý hành chính nhà nước", "B": "Thủ tục hành chính do mọi quy phạm pháp luật quy định", "C": "Thủ tục hành chính có tính mềm dẻo, linh hoạt", "D": "Thủ tục hành chính là thủ tục thực hiện hoạt động quản lý nhà nước"}, "correct": "B"}, {"id": 207, "q": "Ngày 01/10/2022, anh Nguyễn Văn X (không có năng lực trách nhiệm hành chính) đã có hành vi vượt đèn đỏ trong quá trình tham gia giao thông tại phường A, quận B, thành phố C. Vậy anh X có phải chịu trách nhiệm hành chính không?", "options": {"A": "Có", "B": "Không", "C": "Được áp dụng tình tiết giảm nhẹ", "D": "Bị áp dụng tình tiết tăng nặng"}, "correct": "B"}, {"id": 126, "q": "Khẳng định nào sau đây không phải yêu cầu về tính hợp lý của quyết định hành chính?", "options": {"A": "Bảo đảm lợi ích của Nhà nước và nguyện vọng của nhân dân", "B": "Quyết định hành chính phải có tính dự báo", "C": "Ban hành theo đúng trình tự, thủ tục và hình thức do pháp luật quy định", "D": "Quyết định hành chính phải có tính khả thi"}, "correct": "C"}, {"id": 178, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), \"Tình thế của cá nhân, tổ chức vì muốn tránh một nguy cơ đang thực tế đe dọa lợi ích của Nhà nước, của tổ chức, quyền, lợi ích chính đáng của mình hoặc của người khác mà không còn cách nào khác là phải gây một thiệt hại nhỏ hơn thiệt hại cần ngăn ngừa\", được gọi là:", "options": {"A": "Tình thế cấp thiết", "B": "Sự kiện bất ngờ", "C": "Sự kiện bất khả kháng", "D": "Phòng vệ chính đáng"}, "correct": "A"}, {"id": 188, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), xử phạt vi phạm hành chính không lập biên bản được áp dụng trong trường hợp nào sau đây?", "options": {"A": "Phạt tiền đến 200.000 đồng đối với tổ chức", "B": "Phạt tiền đến 300.000 đồng đối với tổ chức", "C": "Phạt tiền đến 400.000 đồng đối với tổ chức", "D": "Phạt tiền đến 500.000 đồng đối với tổ chức"}, "correct": "D"}, {"id": 113, "q": "Đặc điểm của quyết định hành chính bao gồm:", "options": {"A": "Nội dung nhằm thực hiện việc quản lý hành chính nhà nước", "B": "Tính dưới luật", "C": "Được nhiều chủ thể trong hệ thống cơ quan hành chính nhà nước ban hành", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 184, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), chủ thể nào có thẩm quyền quyết định áp dụng biện pháp đưa vào trường giáo dưỡng?", "options": {"A": "Chủ tịch Ủy ban nhân dân cấp xã", "B": "Chủ tịch Ủy ban nhân dân cấp huyện", "C": "Tòa án nhân dân cấp huyện", "D": "Viện kiểm sát nhân dân cấp huyện"}, "correct": "C"}, {"id": 116, "q": "Trường hợp nào sau đây là yêu cầu về tính hợp pháp của quyết định hành chính?", "options": {"A": "Bảo đảm lợi ích của Nhà nước và nguyện vọng của nhân dân", "B": "Quyết định hành chính phải có tính dự báo, tính khả thi", "C": "Ngôn ngữ phải rõ ràng, dễ hiểu, các thuật ngữ pháp lý phải chính xác, không được đa nghĩa", "D": "Nội dung không trái với Hiến pháp và luật"}, "correct": "D"}, {"id": 192, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), trường hợp nào sau đây không phải biện pháp ngăn chặn và bảo đảm xử lý vi phạm hành chính?", "options": {"A": "Tạm giữ người", "B": "Áp giải người vi phạm", "C": "Khám người", "D": "Buộc khôi phục lại tình trạng ban đầu"}, "correct": "D"}, {"id": 203, "q": "Ngày 01/3/2023, anh Nguyễn Văn H, là công an Quận X (tỉnh Y), có hành vi không đội mũ bảo hiểm trong quá trình tham gia giao thông. Vậy anh H là công an có bị xử lý vi phạm hành chính không?", "options": {"A": "Bị xử lý vi phạm hành chính như đối với công dân khác", "B": "Không bị xử lý vi phạm hành chính", "C": "Được áp dụng tình tiết giảm nhẹ", "D": "Bị áp dụng tình tiết tăng nặng"}, "correct": "A"}, {"id": 219, "q": "Ngày 10/10/2023, công ty TNHH LA (được thành lập theo đúng quy định của pháp luật), thực hiện hành vi vi phạm hành chính và bị cơ quan có thẩm quyền ra quyết định xử phạt với hình thức phạt tiền (cụ thể 400.000 đồng). Với mức phạt này Công ty TNHH LA sẽ bị áp dụng thủ tục xử phạt nào sau đây (biết rằng vi phạm hành chính này không cần sử dụng phương tiện, thiết bị kỹ thuật, nghiệp vụ để phát hiện)?", "options": {"A": "Xử phạt vi phạm hành chính không lập biên bản", "B": "Xử phạt vi phạm hành chính lập biên bản", "C": "Xác minh sau đó 07 ngày sẽ ban hành quyết định xử phạt vi phạm hành chính", "D": "Xác minh sau đó 10 ngày sẽ ban hành quyết định xử phạt vi phạm hành chính"}, "correct": "A"}, {"id": 206, "q": "Anh Nguyễn Văn A (15 tuổi, trú tại xã B, huyện C, tỉnh D), từ 02/02/2022 đến 02/8/2022 anh A đã 2 lần bị xử phạt vi phạm hành chính và bị lập biên bản vi phạm hành chính tại lần vi phạm thứ ba về hành vi gây rối trật tự công cộng. Với hành vi này, anh A bị áp dụng biện pháp giáo dục tại xã, phường, thị trấn. Anh/chị hãy cho biết chủ thể nào có thẩm quyền quyết định áp dụng biện pháp này?", "options": {"A": "Chủ tịch Ủy ban nhân dân xã B", "B": "Chủ tịch Ủy ban nhân dân huyện C", "C": "Chủ tịch Ủy ban nhân dân tỉnh D", "D": "Tòa án nhân dân"}, "correct": "A"}, {"id": 125, "q": "Khẳng định nào sau đây đúng?", "options": {"A": "Quyết định cá biệt được ban hành để giải quyết một công việc cụ thể trên từng lĩnh vực của quản lý hành chính nhà nước (áp dụng một lần, cho một hoặc một số đối tượng nhất định).", "B": "Quyết định cá biệt được áp dụng lặp đi lặp lại nhiều lần", "C": "Quyết định cá biệt được áp dụng cho nhiều đối tượng", "D": "Quyết định cá biệt đưa ra đường lối, chủ trương, chính sách"}, "correct": "A"}, {"id": 175, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), xử phạt vi phạm hành chính là:", "options": {"A": "Việc cá nhân có thẩm quyền xử phạt áp dụng hình thức xử phạt, biện pháp khắc phục hậu quả đối với cá nhân, tổ chức thực hiện hành vi vi phạm hành chính theo quy định của pháp luật về xử phạt vi phạm hành chính.", "B": "Việc cơ quan có thẩm quyền xử phạt áp dụng hình thức xử phạt, biện pháp khắc phục hậu quả đối với cá nhân, tổ chức thực hiện hành vi vi phạm hành chính theo quy định của pháp luật về xử phạt vi phạm hành chính.", "C": "Việc người có thẩm quyền xử phạt áp dụng hình thức xử phạt, biện pháp khắc phục hậu quả đối với cá nhân, tổ chức thực hiện hành vi vi phạm hành chính theo quy định của pháp luật về xử phạt vi phạm hành chính.", "D": "Việc tổ chức có thẩm quyền xử phạt áp dụng hình thức xử phạt, biện pháp khắc phục hậu quả đối với cá nhân, tổ chức thực hiện hành vi vi phạm hành chính theo quy định của pháp luật về xử phạt vi phạm hành chính."}, "correct": "C"}, {"id": 216, "q": "Ngày 29/10/2023, anh Nguyễn Văn A, thực hiện hành vi vi phạm hành chính và bị cơ quan có thẩm quyền ra quyết định xử phạt với hình thức phạt tiền (cụ thể 800.000 đồng). Với mức phạt này anh A sẽ bị áp dụng thủ tục xử phạt nào sau đây?", "options": {"A": "Xử phạt vi phạm hành chính không lập biên bản", "B": "Xử phạt vi phạm hành chính lập biên bản", "C": "Ban hành quyết định xử phạt tại chỗ", "D": "Nộp phạt tại chỗ"}, "correct": "B"}, {"id": 170, "q": "Khẳng định nào sau đây không thuộc các yếu tố cấu thành của vi phạm pháp luật hành chính?", "options": {"A": "Chủ thể, khách thể", "B": "Mặt khách quan", "C": "Mặt chủ quan", "D": "Nội dung"}, "correct": "D"}, {"id": 131, "q": "Nguyên tắc của thủ tục hành chính bao gồm?", "options": {"A": "Nguyên tắc khách quan", "B": "Nguyên tắc công khai, minh bạch", "C": "Nguyên tắc bình đẳng trước pháp luật giữa các bên tham gia thủ tục hành chính", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 183, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), mức phạt tiền trong xử phạt vi phạm hành chính đối với tổ chức từ:", "options": {"A": "50.000 đồng đến 1.000.000.000 đồng", "B": "100.000 đồng đến 1.000.000.000 đồng", "C": "100.000 đồng đến 2.000.000.000 đồng", "D": "100.000 đồng đến 3.000.000.000 đồng"}, "correct": "C"}, {"id": 191, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), thời hạn áp dụng biện pháp giáo dục tại xã, phường, thị trấn là bao lâu?", "options": {"A": "Từ 01 tháng đến 06 tháng.", "B": "Từ 03 tháng đến 06 tháng.", "C": "Từ 06 tháng đến 12 tháng.", "D": "Từ 09 tháng đến 12 tháng."}, "correct": "B"}, {"id": 189, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), không áp dụng biện pháp đưa vào cơ sở giáo dục bắt buộc đối với các trường hợp nào sau đây?", "options": {"A": "Người chưa đủ 18 tuổi", "B": "Nữ trên 55 tuổi, nam trên 60 tuổi", "C": "Người đang mang thai có chứng nhận của cơ sở khám bệnh, chữa bệnh từ tuyến huyện trở lên", "D": "Tất cả các đáp án đều đúng"}, "correct": "D"}, {"id": 114, "q": "Quyết định hành chính có nội dung:", "options": {"A": "Thực hiện hoạt động quản lý hành chính nhà nước", "B": "Thực hiện hoạt động tư pháp", "C": "Thực hiện hoạt động lập pháp", "D": "Thực hiện hoạt động lập pháp và hoạt động tư pháp"}, "correct": "A"}, {"id": 167, "q": "Theo Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), mức phạt tiền trong xử phạt vi phạm hành chính đối với cá nhân từ:", "options": {"A": "50.000 đồng đến 1.000.000.000 đồng", "B": "100.000 đồng đến 1.000.000.000 đồng", "C": "100.000 đồng đến 2.000.000.000 đồng", "D": "100.000 đồng đến 3.000.000.000 đồng"}, "correct": "A"}, {"id": 176, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), biện pháp xử lý hành chính áp dụng đối với trường hợp nào sau đây?", "options": {"A": "Cá nhân vi phạm pháp luật về an ninh, trật tự, an toàn xã hội mà không phải là tội phạm", "B": "Tổ chức vi phạm pháp luật về an ninh, trật tự, an toàn xã hội mà không phải là tội phạm", "C": "Cá nhân và tổ chức vi phạm pháp luật về an ninh, trật tự, an toàn xã hội mà không phải là tội phạm", "D": "Cá nhân vi phạm pháp luật trong mọi lĩnh vực mà không phải là tội phạm"}, "correct": "A"}, {"id": 128, "q": "Khẳng định nào sau đây không phải nguyên tắc của thủ tục hành chính?", "options": {"A": "Nguyên tắc pháp chế", "B": "Nguyên tắc công khai, minh bạch", "C": "Nguyên tắc đơn giản, tiết kiệm, nhanh chóng, kịp thời.", "D": "Nguyên tắc tập trung dân chủ"}, "correct": "D"}, {"id": 169, "q": "Khẳng định nào sau đây không là đặc trưng của trách nhiệm hành chính?", "options": {"A": "Áp dụng ngoài trình tự xét xử của Toà án", "B": "Các chủ thể trong quan hệ không tồn tại quan hệ trực thuộc", "C": "Vi phạm quan hệ tài sản và quan hệ nhân thân diễn ra trong giao dịch dân sự.", "D": "Cơ sở của trách nhiệm pháp lý hành chính là vi phạm hành chính"}, "correct": "C"}, {"id": 211, "q": "Anh Nguyễn Văn A là nhân viên kinh doanh tại doanh nghiệp X. Tháng 11/2023, Anh A xin nghỉ việc để giải quyết việc gia đình, doanh nghiệp X đã trừ ½ tiền lương của anh, A không đồng ý, anh A và Giám đốc doanh nghiệp X xảy ra mâu thuẫn. Trong quá trình giải quyết mâu thuẫn, anh A dùng vũ lực đánh Giám đốc doanh nghiệp X. Theo kết luận giám định, Giám đốc doanh nghiệp X bị suy giảm sức khỏe 7%. Anh/chị hãy xác định vi phạm pháp luật của anh A (biết rằng hành vi lần đầu thực hiện)?", "options": {"A": "Vi phạm hình sự", "B": "Vi phạm hành chính", "C": "Vi phạm dân sự", "D": "Vi phạm kỷ luật"}, "correct": "B"}, {"id": 186, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), chủ thể nào có thẩm quyền quyết định áp dụng biện pháp giáo dục tại xã, phường, thị trấn?", "options": {"A": "Chủ tịch Ủy ban nhân dân cấp xã", "B": "Chủ tịch Ủy ban nhân dân cấp huyện", "C": "Tòa án nhân dân cấp huyện", "D": "Viện kiểm sát nhân dân cấp huyện"}, "correct": "A"}, {"id": 173, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), mỗi vi phạm hành chính được quy định:", "options": {"A": "Một hình thức xử phạt chính", "B": "Hai hình thức xử phạt chính", "C": "Ba hình thức xử phạt chính", "D": "Bốn hình thức xử phạt chính"}, "correct": "A"}, {"id": 165, "q": "Theo quy định của Luật Xử lý vi phạm hành chính năm 2012 (sửa đổi, bổ sung năm 2020), hình thức xử phạt hành chính nào sau đây không áp dụng đối với công dân Việt Nam?", "options": {"A": "Phạt tiền", "B": "Tước quyền sử dụng giấy phép, chứng chỉ hành nghề có thời hạn", "C": "Tịch thu tang vật, phương tiện vi phạm", "D": "Trục xuất"}, "correct": "D"}, {"id": 127, "q": "Theo quy định của Luật Khiếu nại năm 2011, người khiếu nại bao gồm:", "options": {"A": "Chỉ bao gồm công dân, cơ quan, tổ chức", "B": "Chỉ bao gồm cán bộ, công chức", "C": "Công dân, cơ quan, tổ chức hoặc cán bộ, công chức", "D": "Chỉ bao gồm cá nhân, tổ chức"}, "correct": "C"}, {"id": 133, "q": "Chủ thể thực hiện thủ tục hành chính là gì?", "options": {"A": "Chủ thể sử dụng quyền lực nhà nước, nhân danh Nhà nước tiến hành các thủ tục hành chính", "B": "Chủ thể phục tùng quyền lực nhà nước khi tham gia thủ tục hành chính", "C": "Chủ thể giải quyết các thủ tục hành chính", "D": "Mọi chủ thể của thủ tục hành chính"}, "correct": "A"}]}];